5	
6	//#region src/components/InngestMiddleware.d.ts
7	
8	/**
9	 * A middleware that can be registered with Inngest to hook into various
10	 * lifecycles of the SDK and affect input and output of Inngest functionality.
11	 *
12	 * See {@link https://innge.st/middleware}
13	 *
14	 * @example
15	 *
16	 * ```ts
17	 * export const inngest = new Inngest({
18	 *   middleware: [
19	 *     new InngestMiddleware({
20	 *       name: "My Middleware",
21	 *       init: () => {
22	 *         // ...
23	 *       }
24	 *     })
25	 *   ]
26	 * });
27	 * ```
28	 *
29	 * @public
30	 */
31	declare class InngestMiddleware<TOpts extends MiddlewareOptions> implements InngestMiddleware.Like {
32	  get [Symbol.toStringTag](): typeof InngestMiddleware.Tag;
33	  /**
34	   * The name of this middleware. Used primarily for debugging and logging
35	   * purposes.
36	   */
37	  readonly name: TOpts["name"];
38	  /**
39	   * This function is used to initialize your middleware and register any hooks
40	   * you want to use. It will be called once when the SDK is initialized, and
41	   * should be used to store any state you want to use in other parts of your
42	   * middleware.
43	   *
44	   * It can be synchronous or asynchronous, in which case the client will wait
45	   * for it to resolve before continuing to initialize the next middleware.
46	   *
47	   * Multiple clients could be used in the same application with differing
48	   * middleware, so do not store state in global variables or assume that your
49	   * middleware will only be used once.
50	   *
51	   * Must return an object detailing the hooks you want to register.
52	   */
53	  readonly init: TOpts["init"];
54	  constructor({
55	    name,
56	    init
57	  }: TOpts);
58	}
59	declare namespace InngestMiddleware {
60	  const Tag: "Inngest.Middleware";
61	  type Any = InngestMiddleware<MiddlewareOptions>;
62	  interface Like {
63	    readonly [Symbol.toStringTag]: typeof InngestMiddleware.Tag;
64	  }
65	  type Stack = [InngestMiddleware.Like, ...InngestMiddleware.Like[]];
66	}
67	type FnsWithSameInputAsOutput<TRecord extends Record<string, (arg: any) => any>> = { [K in keyof TRecord as Await<TRecord[K]> extends Parameters<TRecord[K]>[0] ? K : Await<TRecord[K]> extends undefined | void ? Parameters<TRecord[K]>[0] extends undefined | void ? K : never : never]: TRecord[K] };
68	type PromisifiedFunctionRecord<TRecord extends Record<string, (arg: any) => any>> = Pick<Partial<{ [K in keyof TRecord]: (...args: Parameters<TRecord[K]>) => Promise<Await<TRecord[K]>> }>, keyof FnsWithSameInputAsOutput<TRecord>> & Omit<Partial<{ [K in keyof TRecord]: (...args: Parameters<TRecord[K]>) => Promise<Parameters<TRecord[K]>[0]> }>, keyof FnsWithSameInputAsOutput<TRecord>>;
69	type RunHookStack = PromisifiedFunctionRecord<Await<MiddlewareRegisterReturn["onFunctionRun"]>>;
70	/**
71	 * Options passed to new {@link InngestMiddleware} instance.
72	 *
73	 * @public
74	 */
75	interface MiddlewareOptions {
76	  /**
77	   * The name of this middleware. Used primarily for debugging and logging
78	   * purposes.
79	   */
80	  name: string;
81	  /**
82	   * This function is used to initialize your middleware and register any hooks
83	   * you want to use. It will be called once when the SDK is initialized, and
84	   * should be used to store any state you want to use in other parts of your
85	   * middleware.
86	   *
87	   * It can be synchronous or asynchronous, in which case the client will wait
88	   * for it to resolve before continuing to initialize the next middleware.
89	   *
90	   * Multiple clients could be used in the same application with differing
91	   * middleware, so do not store state in global variables or assume that your
92	   * middleware will only be used once.
93	   *
94	   * Must return an object detailing the hooks you want to register.
95	   */
96	  init: MiddlewareRegisterFn;
97	}
98	/**
99	 * @public
100	 */
101	type MiddlewareRegisterReturn = {
102	  /**
103	   * This hook is called for every function execution and allows you to hook
104	   * into various stages of a run's lifecycle. Use this to store any state you
105	   * want to use for the entirety of a particular run.
106	   *
107	   * It can be synchronous or asynchronous, in which case the client will wait
108	   * for it to resolve before continuing to initialize the next middleware.
109	   *
110	   * Must return an object detailing the hooks you want to register.
111	   */
112	  onFunctionRun?: (ctx: InitialRunInfo) => MaybePromise<{
113	    /**
114	     * The `input` hook is called once the input for the function has been
115	     * properly set up. This is where you can modify the input before the
116	     * function starts to memoize or execute by returning an object containing
117	     * changes to the context.
118	     *
119	     * For example, to add `foo` to the context, you'd return
120	     * `{ ctx: { foo: "bar" } }`.
121	     *
122	     * @param ctx - The context for the incoming request.
123	     * @param steps - The step data in state. Does not include internal IDs.
124	     */
125	    transformInput?: MiddlewareRunInput;
126	    /**
127	     * The `beforeMemoization` hook is called before the function starts to
128	     * memoize.
129	     */
130	    beforeMemoization?: BlankHook;
131	    /**
132	     * The `afterMemoization` hook is called after the function has finished
133	     * memoizing.
134	     */
135	    afterMemoization?: BlankHook;
136	    /**
137	     * The `beforeExecution` hook is called before the function starts to
138	     * execute. Execution here means that new code is being seen/run for the
