17	/**
18	 * Extracts common context fields from Inngest event data.
19	 * Filters out undefined values so ALS context stays clean.
20	 */
21	function extractEventContext(
22	  data: Record<string, unknown> | undefined
23	): Record<string, unknown> {
24	  if (!data) return {};
25	
26	  const fields: Record<string, unknown> = {
27	    correlationId: data.correlationId,
28	    provider: data.provider,
29	    clerkOrgId: data.clerkOrgId ?? data.orgId,
30	    installationId: data.installationId,
31	  };
32	
33	  return Object.fromEntries(
34	    Object.entries(fields).filter(([, v]) => v !== undefined)
35	  );
36	}
37	
38	/**
39	 * Creates the unified Inngest observability middleware.
40	 *
41	 * Consolidates three capabilities into a single middleware:
42	 * 1. ALS context seeding — auto-enriches all `log.*` calls
43	 * 2. Sentry integration — isolation scope, manual spans, selective error capture
44	 * 3. Step journal — records executed steps via beforeExecution/afterExecution hooks
45	 *
46	 * Replaces `@inngest/middleware-sentry`.
47	 *
48	 * Architecture notes:
49	 * - Uses `startSpanManual` (not `startSpan`) because the span must live across
50	 *   multiple lifecycle hooks. `startSpan` auto-ends when its callback returns,
51	 *   which would close the span immediately after hook registration (~0ms).
52	 *   `startSpanManual` requires explicit `.end()` in `beforeResponse`.
53	 *   (Matches the pattern in `@inngest/middleware-sentry`.)
54	 *
55	 * - Uses `requestStore.enterWith()` instead of `requestStore.run()` because
56	 *   Inngest middleware returns a hooks object that is invoked at different
57	 *   lifecycle points — there's no single callback to wrap with `.run()`.
58	 *   Cleanup is guaranteed by the serverless request boundary (each Inngest
59	 *   function run is a separate HTTP request). This diverges from the tRPC
60	 *   middleware's `withRequestContext()` pattern, which is possible because
61	 *   tRPC has a single `next()` callback to wrap.
62	 */
63	export function createInngestObservabilityMiddleware() {
64	  return new InngestMiddleware({
65	    name: "lightfast:observability",
66	
67	    init() {
68	      return {
69	        onFunctionRun({ ctx, fn }) {
70	          const eventData =
71	            (ctx.event?.data as Record<string, unknown>) ?? {};
72	          const eventContext = extractEventContext(eventData);
73	
74	          // Generate correlationId from runId for cron functions with no event data
75	          const correlationId =
76	            (eventContext.correlationId as string | undefined) ?? ctx.runId;
77	
78	          const alsContext = {
79	            requestId: ctx.runId,
80	            inngestFunctionId: fn.id,
81	            inngestEventName: ctx.event?.name,
82	            ...eventContext,
83	            correlationId,
84	          };
85	
86	          const startTime = Date.now();
87	          let execStartTime: number | undefined;
88	
89	          // Wrap everything in a Sentry isolation scope (synchronous — matches sentryMiddleware)
90	          return withIsolationScope((scope) => {
91	            scope.setTag("inngest.function.id", fn.id);
92	            scope.setTag("inngest.run.id", ctx.runId);
93	            if (ctx.event?.name) {
94	              scope.setTag("inngest.event.name", ctx.event.name);
95	            }
96	
97	            // startSpanManual: span lives until explicit .end() in beforeResponse
98	            return startSpanManual(
99	              {
100	                name: `inngest/${fn.id}`,
101	                op: "function.inngest",
102	                attributes: {
103	                  [SEMANTIC_ATTRIBUTE_SENTRY_SOURCE]: "route",
104	                  [SEMANTIC_ATTRIBUTE_SENTRY_ORIGIN]:
105	                    "auto.function.inngest.middleware",
106	                  "inngest.run.id": ctx.runId,
107	                  "inngest.event.name": ctx.event?.name ?? "unknown",
108	                },
109	                scope,
110	              },
111	              (reqSpan) => {
112	                // Extract Sentry trace ID for log correlation
113	                const traceId = reqSpan.spanContext().traceId;
114	
115	                // Seed ALS context via enterWith (see architecture note above)
116	                const store = createStore({
117	                  ...alsContext,
118	                  ...(traceId && { traceId }),
119	                } as { requestId: string } & Record<string, unknown>);
120	                requestStore.enterWith(store);
121	
122	                pushJournal("info", "function:start");
123	
124	                return {
125	                  // Journal executed steps only (not memoized replays).
126	                  // Inngest calls beforeExecution/afterExecution only for
127	                  // steps that actually run new code — memoized steps skip these.
128	                  beforeExecution() {
129	                    execStartTime = Date.now();
130	                    pushJournal("info", "execution:start");
131	                  },
132	
133	                  afterExecution() {
134	                    const execMs = execStartTime
135	                      ? Date.now() - execStartTime
136	                      : undefined;
137	                    pushJournal("info", "execution:done", {
138	                      ...(execMs !== undefined && { durationMs: execMs }),
139	                    });
140	                  },
141	
142	                  transformOutput({ result, step: stepInfo }) {
143	                    const durationMs = Date.now() - startTime;
144	                    const journal = getJournal();
145	
146	                    if (result.error) {
147	                      const isBusinessError =
148	                        result.error instanceof NonRetriableError;
149	
150	                      pushJournal("error", "function:error", {
151	                        error: result.error.message,
152	                        durationMs,
153	                        isBusinessError,
154	                      });
155	
156	                      // Only capture unexpected errors to Sentry.
157	                      // NonRetriableError = business rejection (filtered event, no connection, etc.)
158	                      if (!isBusinessError) {
159	                        withActiveSpan(reqSpan, () => {
160	                          scope.setTag("inngest.function.id", fn.id);
161	                          scope.setTag("inngest.run.id", ctx.runId);
162	                          scope.setTransactionName(`inngest:${fn.id}`);
163	                        });
