     import { flush, SEMANTIC_ATTRIBUTE_SENTRY_ORIGIN, SEMANTIC_ATTRIBUTE_SENTRY_SOURCE, startSpanManual, withActiveSpan, withIsolationScope } from "@sentry/core";
     import { InngestMiddleware, NonRetriableError } from "@vendor/inngest";
     import type { JournalEntry } from "./context";
     import { createStore, requestStore } from "./context";
     import { log } from "./log/next";

     const MAX_JOURNAL_ENTRIES = 50;

     function extractEventContext(data: Record<string, unknown> | undefined): Record<string, unknown> { ... }

     export function createInngestObservabilityMiddleware() {
       return new InngestMiddleware({
         name: "lightfast:observability",
         init() {
           return {
             onFunctionRun({ ctx, fn }) {
               const fnId = fn.id();  // method, not property
               // ... extract event context, build alsContext ...
               const store = createStore(alsContext as { requestId: string } & Record<string, unknown>);

               // Local journal helper — bypasses ALS (see architecture notes)
               function journal(level, msg, meta?) {
                 if (store.journal.length < MAX_JOURNAL_ENTRIES) {
                   store.journal.push({ ts: Date.now(), level, msg, meta });
                 }
               }
               journal("info", "function:start");

               return withIsolationScope((scope) => {
                 // ... set Sentry tags ...
                 return startSpanManual({...}, (reqSpan) => {
                   // Add traceId to store via mutation
                   store.ctx = { ...store.ctx, traceId };
                   return {
                     beforeMemoization() { requestStore.enterWith(store); },
                     beforeExecution() { journal("info", "execution:start"); },
                     afterExecution() { journal("info", "execution:done", {...}); },
                     transformOutput({ result, step: stepInfo }) {
                       // Uses store.journal directly, not getJournal()
                       // Uses scope.captureException(), not global captureException
                       // NonRetriableError → isBusinessError → skip Sentry
                     },
                     async beforeResponse() { reqSpan.end(); await flush(2000); },
                   };
                 });
               });
             },
           };
         },
       });
     }
