1	/**
2	 * Ingest delivery workflow
3	 *
4	 * Replaces the relay Upstash Workflow (5 steps) + QStash dispatch +
5	 * console ingress Upstash Workflow (2 steps) with a single Inngest function.
6	 *
7	 * Steps:
8	 * 1. resolve-connection — query orgIntegrations, or use preResolved
9	 * 2. transform-and-store — call transformEnvelope, insert ingest log
10	 * 3. emit-event-capture — step.sendEvent("platform/event.capture")
11	 * 4. publish-realtime — Upstash Realtime SSE for console UI
12	 */
13	
14	import { db } from "@db/app/client";
15	import {
16	  gatewayWebhookDeliveries,
17	  orgIngestLogs,
18	  orgIntegrations,
19	} from "@db/app/schema";
20	import type { ProviderSlug } from "@repo/app-providers";
21	import { sanitizePostTransformEvent } from "@repo/app-providers";
22	import type { EventNotification } from "@repo/app-upstash-realtime";
23	import { NonRetriableError } from "@vendor/inngest";
24	import { log } from "@vendor/observability/log/next";
25	import { and, eq } from "drizzle-orm";
26	import { transformEnvelope } from "../../lib/transform";
27	import { inngest } from "../client";
28	
29	export const ingestDelivery = inngest.createFunction(
30	  {
31	    id: "platform/ingest.delivery",
32	    name: "Ingest Delivery",
33	    description:
34	      "Webhook delivery -> transform -> emit event.capture (replaces relay workflow + QStash + console ingress)",
35	    concurrency: {
36	      limit: 20,
37	      key: "event.data.provider",
38	    },
39	    retries: 3,
40	    timeouts: {
41	      start: "1m",
42	      finish: "3m",
43	    },
44	  },
45	  { event: "platform/webhook.received" },
46	  async ({ event, step }) => {
47	    const data = event.data;
48	
49	    // Step 1: Resolve connection from resource ID or use preResolved
50	    const connectionInfo = await step.run("resolve-connection", async () => {
51	      if (data.preResolved) {
52	        return data.preResolved;
53	      }
54	
55	      if (!data.resourceId) {
56	        return null;
57	      }
58	
59	      const rows = await db
60	        .select({
61	          installationId: orgIntegrations.installationId,
62	          orgId: orgIntegrations.clerkOrgId,
63	        })
64	        .from(orgIntegrations)
65	        .where(
66	          and(
67	            eq(orgIntegrations.providerResourceId, data.resourceId),
68	            eq(orgIntegrations.status, "active")
69	          )
70	        )
71	        .limit(1);
72	
73	      const row = rows[0];
74	      if (!row) {
75	        return null;
76	      }
77	
78	      return { connectionId: row.installationId, orgId: row.orgId };
79	    });
80	
81	    if (!connectionInfo?.orgId) {
82	      throw new NonRetriableError("no_connection");
83	    }
84	
85	    // clerkOrgId IS the orgId
86	    const clerkOrgId = connectionInfo.orgId;
87	
88	    log.info("[ingest-delivery] connection resolved", {
89	      clerkOrgId,
90	      provider: data.provider,
91	      deliveryId: data.deliveryId,
92	      correlationId: data.correlationId,
93	    });
94	
95	    // Step 2: Transform envelope and store ingest log
96	    const result = await step.run("transform-and-store", async () => {
97	      const rawEvent = transformEnvelope({
98	        provider: data.provider as ProviderSlug,
99	        eventType: data.eventType,
100	        payload: data.payload,
101	        deliveryId: data.deliveryId,
102	        receivedAt: data.receivedAt,
103	        orgId: connectionInfo.orgId,
104	        connectionId: connectionInfo.connectionId,
105	      });
106	
107	      if (!rawEvent) {
108	        log.info("[ingest-delivery] No transformer, skipping", {
109	          provider: data.provider,
110	          eventType: data.eventType,
111	          deliveryId: data.deliveryId,
112	          correlationId: data.correlationId,
113	        });
114	        return { status: "unsupported" as const };
115	      }
116	
117	      const sourceEvent = sanitizePostTransformEvent(rawEvent);
118	
119	      const [record] = await db
120	        .insert(orgIngestLogs)
121	        .values({
122	          clerkOrgId,
123	          deliveryId: data.deliveryId,
124	          sourceEvent,
125	          receivedAt: new Date(data.receivedAt).toISOString(),
126	          ingestionSource: "webhook",
127	        })
128	        .returning({ id: orgIngestLogs.id });
129	
130	      if (!record) {
131	        throw new Error("Failed to insert ingest log");
132	      }
133	
134	      log.info("[ingest-delivery] event stored", {
135	        ingestLogId: record.id,
136	        clerkOrgId,
137	        deliveryId: data.deliveryId,
138	        correlationId: data.correlationId,
139	      });
140	
141	      return {
142	        status: "transformed" as const,
143	        sourceEvent,
144	        ingestLogId: record.id,
145	      };
146	    });
147	
148	    // Unsupported event type — return early, no downstream events
149	    if (result.status === "unsupported") {
150	      await step.run("mark-delivery-skipped", async () => {
151	        await db
152	          .update(gatewayWebhookDeliveries)
153	          .set({ status: "skipped" })
154	          .where(eq(gatewayWebhookDeliveries.deliveryId, data.deliveryId));
155	      });
156	      return {
157	        status: "unsupported",
158	        provider: data.provider,
159	        eventType: data.eventType,
160	      };
161	    }
162	
163	    // Step 3: Emit platform/event.capture to trigger the neural pipeline
164	    await step.sendEvent("emit-event-capture", {
165	      name: "platform/event.capture" as const,
166	      data: {
167	        clerkOrgId,
168	        sourceEvent: result.sourceEvent,
169	        ingestionSource: "webhook",
170	        ingestLogId: result.ingestLogId,
171	        correlationId: data.correlationId,
172	      },
173	    });
174	
175	    // Step 4: Publish to Upstash Realtime for console SSE
176	    await step.run("publish-realtime", async () => {
177	      const { realtime } = await import("@repo/app-upstash-realtime");
178	      const channel = realtime.channel(`org-${clerkOrgId}`);
179	      await channel.emit("org.event", {
180	        eventId: result.ingestLogId,
181	        clerkOrgId,
182	        sourceEvent: result.sourceEvent,
183	      } satisfies EventNotification);
184	
185	      log.info("[ingest-delivery] realtime notification published", {
186	        clerkOrgId,
187	        ingestLogId: result.ingestLogId,
188	        correlationId: data.correlationId,
189	      });
190	    });
191	
192	    // Step 5: Mark delivery as processed
193	    await step.run("mark-delivery-processed", async () => {
194	      await db
195	        .update(gatewayWebhookDeliveries)
196	        .set({ status: "processed" })
197	        .where(eq(gatewayWebhookDeliveries.deliveryId, data.deliveryId));
198	    });
199	
200	    return {
201	      status: "delivered",
202	      clerkOrgId,
203	      ingestLogId: result.ingestLogId,
204	    };
205	  }
206	);
207

