1	/**
2	 * Event store workflow (fast path)
3	 *
4	 * Stores facts from PostTransformEvents: event row + entities + junction rows.
5	 * No LLM calls, no embeddings — completes in <2s.
6	 *
7	 * Workflow steps:
8	 * 1. Check for duplicate events (idempotency)
9	 * 2. Check if event is allowed by source config (filtering)
10	 * 3. Evaluate significance (stored as metadata, not a gate)
11	 * 4. Extract entities (structural categories from relations)
12	 * 5. Store event row
13	 * 6. Upsert entities + create junction rows
14	 * 7. Emit entity.upserted (triggers entity-graph -> entity-embed chain)
15	 * 8. Complete job
16	 */
17	
18	import { db } from "@db/app/client";
19	import {
20	  orgEntities,
21	  orgEventEntities,
22	  orgEvents,
23	  orgIntegrations,
24	} from "@db/app/schema";
25	import type { ProviderConfig } from "@repo/app-providers";
26	import { deriveObservationType, getBaseEventType } from "@repo/app-providers";
27	import type {
28	  EntityCategory,
29	  EventCaptureInput,
30	  EventCaptureOutputFailure,
31	  EventCaptureOutputFiltered,
32	  EventCaptureOutputSuccess,
33	  ExtractedEntity,
34	} from "@repo/app-validation";
35	import { NonRetriableError } from "@vendor/inngest";
36	import { log } from "@vendor/observability/log/next";
37	import { and, eq, sql } from "drizzle-orm";
38	import { nanoid } from "nanoid";
39	import {
40	  extractEntities,
41	  extractFromRelations,
42	} from "../../lib/entity-extraction-patterns";
43	import { completeJob, createJob, updateJobStatus } from "../../lib/jobs";
44	import { scoreSignificance } from "../../lib/scoring";
45	import { inngest } from "../client";
46	import { createNeuralOnFailureHandler } from "../on-failure-handler";
47	
48	const STRUCTURAL_TYPES = new Set([
49	  "commit",
50	  "branch",
51	  "pr",
52	  "issue",
53	  "deployment",
54	]);
55	
56	/**
57	 * Check if an event type is allowed for a source based on providerConfig.sync.events
58	 */
59	function isEventAllowed(
60	  providerConfig: ProviderConfig | null | undefined,
61	  baseEventType: string
62	): boolean {
63	  const events = providerConfig?.sync?.events;
64	  if (!events || events.length === 0) {
65	    return true;
66	  }
67	  return events.includes(baseEventType);
68	}
69	
70	/**
71	 * Event store workflow
72	 *
73	 * Fast path: stores facts only. No LLM, no embeddings.
74	 * Emits entity.upserted to trigger the entity-graph -> entity-embed chain.
75	 */
76	export const platformEventStore = inngest.createFunction(
77	  {
78	    id: "platform/event.store",
79	    name: "Event Store",
80	    description: "Stores engineering events (fast path)",
81	    retries: 3,
82	
83	    // Idempotency by org + source ID to prevent duplicate observations per org
84	    idempotency:
85	      "event.data.clerkOrgId + '-' + event.data.sourceEvent.sourceId",
86	
87	    // Concurrency limit per org
88	    concurrency: {
89	      limit: 10,
90	      key: "event.data.clerkOrgId",
91	    },
92	
93	    timeouts: {
94	      start: "1m",
95	      finish: "2m",
96	    },
97	
98	    // Handle failures gracefully - complete job as failed
99	    onFailure: createNeuralOnFailureHandler("platform/event.capture", {
100	      logMessage: "Neural observation store failed",
101	      logContext: ({ clerkOrgId, sourceEvent }) => ({
102	        clerkOrgId,
103	        sourceId: sourceEvent.sourceId,
104	      }),
105	      buildOutput: ({ data: { sourceEvent }, error }) =>
106	        ({
107	          inngestFunctionId: "event.capture",
108	          status: "failure",
109	          sourceId: sourceEvent.sourceId,
110	          error,
111	        }) satisfies EventCaptureOutputFailure,
112	    }),
113	  },
114	  { event: "platform/event.capture" },
115	  async ({ event, step }) => {
116	    const { clerkOrgId, sourceEvent, ingestLogId, correlationId } = event.data;
117	
118	    // Generate replay-safe values inside steps so they're memoized across retries.
119	    const { externalId, startTime } = await step.run(
120	      "generate-replay-safe-ids",
121	      () => ({
122	        externalId: nanoid(),
123	        startTime: Date.now(),
124	      })
125	    );
126	
127	    log.info("[event-store] storing observation", {
128	      clerkOrgId,
129	      externalId,
130	      provider: sourceEvent.provider,
131	      eventType: sourceEvent.eventType,
132	      sourceId: sourceEvent.sourceId,
133	      ingestLogId,
134	      correlationId,
135	    });
136	
137	    // Step 0: Create job record for tracking
138	    const inngestRunId =
139	      event.id ?? `neural-obs-${sourceEvent.sourceId}-${startTime}`;
140	    const jobId = await step.run("create-job", async () => {
141	      return createJob({
142	        clerkOrgId,
143	        inngestRunId,
144	        inngestFunctionId: "platform/event.capture",
145	        name: `Capture ${sourceEvent.provider}/${sourceEvent.eventType}`,
146	        trigger: "webhook",
147	        input: {
148	          inngestFunctionId: "event.capture",
149	          sourceId: sourceEvent.sourceId,
150	          source: sourceEvent.provider,
151	          sourceType: sourceEvent.eventType,
152	          title: sourceEvent.title,
153	        } satisfies EventCaptureInput,
154	      });
155	    });
156	
157	    await step.run("update-job-running", async () => {
158	      await updateJobStatus(jobId, "running");
159	    });
160	
161	    // Step 1: Check for duplicate
162	    const existing = await step.run("check-duplicate", async () => {
163	      const obs = await db.query.orgEvents.findFirst({
164	        where: and(
165	          eq(orgEvents.clerkOrgId, clerkOrgId),
166	          eq(orgEvents.sourceId, sourceEvent.sourceId)
167	        ),
168	      });
169	
170	      if (obs) {
171	        log.info("[event-store] observation already exists, skipping", {
172	          observationId: obs.id,
173	          sourceId: sourceEvent.sourceId,
174	        });
175	      }
176	
177	      return obs ?? null;
178	    });
179	
180	    if (existing) {
181	      await step.run("complete-job-duplicate", async () => {
182	        await completeJob({
183	          jobId,
184	          status: "completed",
185	          output: {
186	            inngestFunctionId: "event.capture",
187	            status: "filtered",
188	            reason: "duplicate",
189	            sourceId: sourceEvent.sourceId,
190	          } satisfies EventCaptureOutputFiltered,
191	        });
192	      });
193	
194	      return {
195	        status: "duplicate",
196	        observationId: existing.id,
197	        duration: Date.now() - startTime,
198	      };
199	    }
200	
201	    // Step 2: Check if event is allowed by source config
202	    const gateResult = await step.run("check-event-allowed", async () => {
203	      const attributes = sourceEvent.attributes;
204	
205	      let resourceId: string | undefined;
206	      switch (sourceEvent.provider) {
207	        case "github":
208	          resourceId =
209	            attributes.repoId != null ? String(attributes.repoId) : undefined;
210	          break;
211	        case "vercel":
212	          resourceId =
213	            attributes.projectId != null
214	              ? String(attributes.projectId)
215	              : undefined;
216	          break;
217	        case "sentry":
218	          resourceId =
219	            attributes.projectId != null
220	              ? String(attributes.projectId)
221	              : undefined;
222	          break;
223	        case "linear":
224	          resourceId =
225	            attributes.teamId != null ? String(attributes.teamId) : undefined;
226	          break;
227	        default:
228	          resourceId = undefined;
229	      }
230	
231	      if (!resourceId) {
232	        log.info("[event-store] no resource ID, rejecting event", {
233	          provider: sourceEvent.provider,
234	          eventType: sourceEvent.eventType,
235	        });
236	        return {
237	          allowed: false as const,
238	          reason: "event_not_allowed" as const,
239	        };
240	      }
241	
242	      const integration = await db.query.orgIntegrations.findFirst({
243	        where: and(
244	          eq(orgIntegrations.clerkOrgId, clerkOrgId),
245	          eq(orgIntegrations.providerResourceId, resourceId)
246	        ),
247	      });
248	
249	      if (!integration) {
250	        log.info("[event-store] integration not found, rejecting event", {
251	          clerkOrgId,
252	          resourceId,
253	          provider: sourceEvent.provider,
254	        });
255	        return {
256	          allowed: false as const,
257	          reason: "event_not_allowed" as const,
258	        };
259	      }
260	
261	      // Gate 2: check integration is active
262	      if (integration.status !== "active") {
263	        log.info("[event-store] integration not active, rejecting (Gate 2)", {
264	          clerkOrgId,
265	          resourceId,
266	          provider: sourceEvent.provider,
267	          integrationStatus: integration.status,
268	          statusReason: integration.statusReason,
269	        });
270	        return {
271	          allowed: false as const,
272	          reason: "inactive_connection" as const,
273	        };
274	      }
275	
276	      const baseEventType = getBaseEventType(
277	        sourceEvent.provider,
278	        sourceEvent.eventType
279	      );
280	      const allowed = isEventAllowed(integration.providerConfig, baseEventType);
281	
282	      if (!allowed) {
283	        log.info("[event-store] event filtered by provider config", {
284	          clerkOrgId,
285	          resourceId,
286	          eventType: sourceEvent.eventType,
287	          baseEventType,
288	          configuredEvents: integration.providerConfig?.sync?.events,
289	        });
290	      }
291	
292	      return {
293	        allowed,
294	        reason: allowed ? ("allowed" as const) : ("event_not_allowed" as const),
295	      };
296	    });
297	
298	    if (!gateResult.allowed) {
299	      const filteredReason =
300	        gateResult.reason === "inactive_connection"
301	          ? ("inactive_connection" as const)
302	          : ("event_not_allowed" as const);
303	
304	      await step.run("complete-job-filtered", async () => {
305	        await completeJob({
306	          jobId,
307	          status: "completed",
308	          output: {
309	            inngestFunctionId: "event.capture",
310	            status: "filtered",
311	            reason: filteredReason,
312	            sourceId: sourceEvent.sourceId,
313	          } satisfies EventCaptureOutputFiltered,
314	        });
315	      });
316	
317	      return {
318	        status: "filtered",
319	        reason:
320	          filteredReason === "inactive_connection"
321	            ? "Integration is not active"
322	            : "Event type not enabled in source config",
323	        duration: Date.now() - startTime,
324	      };
325	    }
326	
327	    // Step 3: Evaluate significance (metadata annotation, not a gate)
328	    const significance = await step.run("evaluate-significance", () => {
329	      return scoreSignificance(sourceEvent);
330	    });
331	
332	    // Step 4: Extract entities (structural categories from relations)
333	    const extractedEntities = await step.run("extract-entities", () => {
334	      const textEntities = extractEntities(sourceEvent.title, sourceEvent.body);
335	      const refEntities = extractFromRelations(sourceEvent.relations);
336	
337	      // Primary entity from sourceEvent.entity — always upserted with highest
338	      // confidence so entity-embed can always find it by (clerkOrgId, category, key).
339	      // value is undefined so refLabel on the junction row stays null (it has no
340	      // relationship-type label — it IS the event's primary subject).
341	      const primaryEntityExtracted: ExtractedEntity = {
342	        category: sourceEvent.entity.entityType as EntityCategory,
343	        key: sourceEvent.entity.entityId,
344	        value: undefined,
345	        confidence: 1.0,
346	        evidence: `Primary entity: ${sourceEvent.entity.entityType}`,
347	        state: sourceEvent.entity.state ?? undefined,
348	        url: sourceEvent.entity.url ?? undefined,
349	      };
350	
351	      // Primary entity first — Map insertion order preserved, so it is always
352	      // at index 0 of deduplicated (used to retrieve externalId after upsert).
353	      const allEntities = [
354	        primaryEntityExtracted,
355	        ...textEntities,
356	        ...refEntities,
357	      ];
358	      const entityMap = new Map<string, ExtractedEntity>();
359	
360	      for (const entity of allEntities) {
361	        const key = `${entity.category}:${entity.key.toLowerCase()}`;
362	        const existingEntity = entityMap.get(key);
363	        if (!existingEntity || existingEntity.confidence < entity.confidence) {
364	          entityMap.set(key, entity);
365	        }
366	      }
367	
368	      const deduplicated = Array.from(entityMap.values());
369	      return deduplicated.slice(0, 50); // MAX_ENTITIES_PER_OBSERVATION
370	    });
371	
372	    // Step 5: Store observation row
373	    const observation = await step.run("store-observation", async () => {
374	      const observationType = deriveObservationType(
375	        sourceEvent.provider,
376	        sourceEvent.eventType
377	      );
378	
379	      const [obs] = await db
380	        .insert(orgEvents)
381	        .values({
382	          externalId,
383	          clerkOrgId,
384	          occurredAt: sourceEvent.occurredAt,
385	          observationType,
386	          title: sourceEvent.title,
387	          content: sourceEvent.body,
388	          source: sourceEvent.provider,
389	          sourceType: sourceEvent.eventType,
390	          sourceId: sourceEvent.sourceId,
391	          sourceReferences: sourceEvent.relations,
392	          metadata: sourceEvent.attributes,
393	          ingestionSource: event.data.ingestionSource ?? "webhook",
394	          ingestLogId: ingestLogId ?? null,
395	          significanceScore: significance.score,
396	        })
397	        .returning();
398	
399	      if (!obs) {
400	        throw new NonRetriableError("Failed to insert observation");
401	      }
402	
403	      log.info("[event-store] observation stored", {
404	        observationId: obs.id,
405	        externalId: obs.externalId,
406	        observationType,
407	        ingestLogId,
408	        correlationId,
409	      });
410	
411	      return obs;
412	    });
413	
414	    // Step 6: Upsert entities and create junction rows
415	    const entityUpsertResult = await step.run(
416	      "upsert-entities-and-junctions",
417	      async () => {
418	        if (extractedEntities.length === 0) {
419	          return { count: 0, primaryEntityExternalId: null as string | null };
420	        }
421	
422	        // Upsert each entity and get back its ID + externalId for junction inserts.
423	        // externalId is needed to emit entity.upserted with the stable Pinecone vector key.
424	        const entityResults = await Promise.all(
425	          extractedEntities.map((entity) =>
426	            db
427	              .insert(orgEntities)
428	              .values({
429	                clerkOrgId,
430	                category: entity.category,
431	                key: entity.key,
432	                value: entity.value,
433	                evidenceSnippet: entity.evidence,
434	                confidence: entity.confidence,
435	                state: entity.state ?? null,
436	                url: entity.url ?? null,
437	              })
438	              .onConflictDoUpdate({
439	                target: [
440	                  orgEntities.clerkOrgId,
441	                  orgEntities.category,
442	                  orgEntities.key,
443	                ],
444	                set: {
445	                  lastSeenAt: sql`GREATEST(${orgEntities.lastSeenAt}, excluded.${sql.identifier(orgEntities.lastSeenAt.name)})`,
446	                  occurrenceCount: sql`${orgEntities.occurrenceCount} + 1`,
447	                  updatedAt: new Date().toISOString(),
448	                  state: sql`CASE WHEN excluded.${sql.identifier(orgEntities.lastSeenAt.name)} > ${orgEntities.lastSeenAt} THEN excluded.${sql.identifier(orgEntities.state.name)} ELSE ${orgEntities.state} END`,
449	                  url: sql`COALESCE(excluded.${sql.identifier(orgEntities.url.name)}, ${orgEntities.url})`,
450	                },
451	              })
452	              .returning({
453	                id: orgEntities.id,
454	                externalId: orgEntities.externalId,
455	              })
456	          )
457	        );
458	
459	        // Primary entity is always at index 0 (inserted first in extractedEntities,
460	        // Map insertion order preserved, and confidence 1.0 ensures it wins dedup).
461	        const primaryEntityExternalId =
462	          entityResults[0]?.[0]?.externalId ?? null;
463	
464	        // Create junction rows mapping entities to this observation
465	        const junctionRows = entityResults
466	          .map((result, i) => {
467	            const entityId = result[0]?.id;
468	            if (entityId === undefined) {
469	              return null;
470	            }
471	            const entity = extractedEntities[i]!;
472	            return {
473	              entityId,
474	              eventId: observation.id,
475	              clerkOrgId,
476	              category: entity.category,
477	              // Only structural ref entities carry a contextual relationship label.
478	              // The primary entity (index 0) has value=undefined -> refLabel=null.
479	              refLabel: STRUCTURAL_TYPES.has(entity.category)
480	                ? (entity.value ?? null)
481	                : null,
482	            };
483	          })
484	          .filter((row): row is NonNullable<typeof row> => row !== null);
485	
486	        if (junctionRows.length > 0) {
487	          await db
488	            .insert(orgEventEntities)
489	            .values(junctionRows)
490	            .onConflictDoNothing();
491	        }
492	
493	        log.info("[event-store] entities and junctions stored", {
494	          observationId: observation.id,
495	          entitiesStored: junctionRows.length,
496	          ingestLogId,
497	          correlationId,
498	        });
499	
500	        return { count: junctionRows.length, primaryEntityExternalId };
501	      }
502	    );
503	
504	    // Build entity refs for entity-graph downstream step.
505	    const entityRefs = [
506	      {
507	        type: sourceEvent.entity.entityType,
508	        key: sourceEvent.entity.entityId,
509	        label: null,
510	      },
511	      ...sourceEvent.relations.map((rel) => ({
512	        type: rel.entityType,
513	        key: rel.entityId,
514	        label: rel.relationshipType,
515	      })),
516	    ];
517	
518	    // Step 7: Emit entity.upserted (triggers entity-graph -> entity-embed chain)
519	    if (entityUpsertResult.primaryEntityExternalId) {
520	      await step.sendEvent("emit-downstream-events", {
521	        name: "platform/entity.upserted" as const,
522	        data: {
523	          clerkOrgId,
524	          entityExternalId: entityUpsertResult.primaryEntityExternalId,
525	          entityType: sourceEvent.entity.entityType,
