/**
 * Event store workflow (fast path)
 *
 * Stores facts from PostTransformEvents: event row + entities + junction rows.
 * No LLM calls, no embeddings — completes in <2s.
 *
 * Workflow steps:
 * 1. Check for duplicate events (idempotency)
 * 2. Check if event is allowed by source config (filtering)
 * 3. Evaluate significance (stored as metadata, not a gate)
 * 4. Extract entities (structural categories from relations)
 * 5. Store event row
 * 6. Upsert entities + create junction rows
 * 7. Emit entity.upserted (triggers entity-graph -> entity-embed chain)
 * 8. Complete job
 */

import { db } from "@db/app/client";
import {
  orgEntities,
  orgEventEntities,
  orgEvents,
  orgIntegrations,
} from "@db/app/schema";
import type { ProviderConfig } from "@repo/app-providers";
import { deriveObservationType, getBaseEventType } from "@repo/app-providers";
import type {
  EntityCategory,
  EventCaptureInput,
  EventCaptureOutputFailure,
  EventCaptureOutputFiltered,
  EventCaptureOutputSuccess,
  ExtractedEntity,
} from "@repo/app-validation";
import { NonRetriableError } from "@vendor/inngest";
import { log } from "@vendor/observability/log/next";
import { and, eq, sql } from "drizzle-orm";
import { nanoid } from "nanoid";
import {
  extractEntities,
  extractFromRelations,
} from "../../lib/entity-extraction-patterns";
import { completeJob, createJob, updateJobStatus } from "../../lib/jobs";
import { scoreSignificance } from "../../lib/scoring";
import { inngest } from "../client";
import { createNeuralOnFailureHandler } from "../on-failure-handler";

const STRUCTURAL_TYPES = new Set([
  "commit",
  "branch",
  "pr",
  "issue",
  "deployment",
]);

/**
 * Check if an event type is allowed for a source based on providerConfig.sync.events
 */
function isEventAllowed(
  providerConfig: ProviderConfig | null | undefined,
  baseEventType: string
): boolean {
  const events = providerConfig?.sync?.events;
  if (!events || events.length === 0) {
    return true;
  }
  return events.includes(baseEventType);
}

/**
 * Event store workflow
 *
 * Fast path: stores facts only. No LLM, no embeddings.
 * Emits entity.upserted to trigger the entity-graph -> entity-embed chain.
 */
export const platformEventStore = inngest.createFunction(
  {
    id: "platform/event.store",
    name: "Event Store",
    description: "Stores engineering events (fast path)",
    retries: 3,

    // Idempotency by org + source ID to prevent duplicate observations per org
    idempotency:
      "event.data.clerkOrgId + '-' + event.data.sourceEvent.sourceId",

    // Concurrency limit per org
    concurrency: {
      limit: 10,
      key: "event.data.clerkOrgId",
    },

    timeouts: {
      start: "1m",
      finish: "2m",
    },

    // Handle failures gracefully - complete job as failed
    onFailure: createNeuralOnFailureHandler("platform/event.capture", {
      logMessage: "Neural observation store failed",
      logContext: ({ clerkOrgId, sourceEvent }) => ({
        clerkOrgId,
        sourceId: sourceEvent.sourceId,
      }),
      buildOutput: ({ data: { sourceEvent }, error }) =>
        ({
          inngestFunctionId: "event.capture",
          status: "failure",
          sourceId: sourceEvent.sourceId,
          error,
        }) satisfies EventCaptureOutputFailure,
    }),
  },
  { event: "platform/event.capture" },
  async ({ event, step }) => {
    const { clerkOrgId, sourceEvent, ingestLogId, correlationId } = event.data;

    // Generate replay-safe values inside steps so they're memoized across retries.
    const { externalId, startTime } = await step.run(
      "generate-replay-safe-ids",
      () => ({
        externalId: nanoid(),
        startTime: Date.now(),
      })
    );

    log.info("[event-store] storing observation", {
      clerkOrgId,
      externalId,
      provider: sourceEvent.provider,
      eventType: sourceEvent.eventType,
      sourceId: sourceEvent.sourceId,
      ingestLogId,
      correlationId,
    });

    // Step 0: Create job record for tracking
    const inngestRunId =
      event.id ?? `neural-obs-${sourceEvent.sourceId}-${startTime}`;
    const jobId = await step.run("create-job", async () => {
      return createJob({
        clerkOrgId,
        inngestRunId,
        inngestFunctionId: "platform/event.capture",
        name: `Capture ${sourceEvent.provider}/${sourceEvent.eventType}`,
        trigger: "webhook",
        input: {
          inngestFunctionId: "event.capture",
          sourceId: sourceEvent.sourceId,
          source: sourceEvent.provider,
          sourceType: sourceEvent.eventType,
          title: sourceEvent.title,
        } satisfies EventCaptureInput,
      });
    });

    await step.run("update-job-running", async () => {
      await updateJobStatus(jobId, "running");
    });

    // Step 1: Check for duplicate
    const existing = await step.run("check-duplicate", async () => {
      const obs = await db.query.orgEvents.findFirst({
        where: and(
          eq(orgEvents.clerkOrgId, clerkOrgId),
          eq(orgEvents.sourceId, sourceEvent.sourceId)
        ),
      });

      if (obs) {
        log.info("[event-store] observation already exists, skipping", {
          observationId: obs.id,
          sourceId: sourceEvent.sourceId,
        });
      }

      return obs ?? null;
    });

    if (existing) {
      await step.run("complete-job-duplicate", async () => {
        await completeJob({
          jobId,
          status: "completed",
          output: {
            inngestFunctionId: "event.capture",
            status: "filtered",
            reason: "duplicate",
            sourceId: sourceEvent.sourceId,
          } satisfies EventCaptureOutputFiltered,
        });
      });

      return {
        status: "duplicate",
        observationId: existing.id,
        duration: Date.now() - startTime,
      };
    }

    // Step 2: Check if event is allowed by source config
    const gateResult = await step.run("check-event-allowed", async () => {
      const attributes = sourceEvent.attributes;

      let resourceId: string | undefined;
      switch (sourceEvent.provider) {
        case "github":
          resourceId =
            attributes.repoId != null ? String(attributes.repoId) : undefined;
          break;
        case "vercel":
          resourceId =
            attributes.projectId != null
              ? String(attributes.projectId)
              : undefined;
          break;
        case "sentry":
          resourceId =
            attributes.projectId != null
              ? String(attributes.projectId)
              : undefined;
          break;
        case "linear":
          resourceId =
            attributes.teamId != null ? String(attributes.teamId) : undefined;
          break;
        default:
          resourceId = undefined;
      }

      if (!resourceId) {
        log.info("[event-store] no resource ID, rejecting event", {
          provider: sourceEvent.provider,
          eventType: sourceEvent.eventType,
        });
        return {
          allowed: false as const,
          reason: "event_not_allowed" as const,
        };
      }

      const integration = await db.query.orgIntegrations.findFirst({
        where: and(
          eq(orgIntegrations.clerkOrgId, clerkOrgId),
          eq(orgIntegrations.providerResourceId, resourceId)
        ),
      });

      if (!integration) {
        log.info("[event-store] integration not found, rejecting event", {
          clerkOrgId,
          resourceId,
          provider: sourceEvent.provider,
        });
        return {
          allowed: false as const,
          reason: "event_not_allowed" as const,
        };
      }

      // Gate 2: check integration is active
      if (integration.status !== "active") {
        log.info("[event-store] integration not active, rejecting (Gate 2)", {
          clerkOrgId,
          resourceId,
          provider: sourceEvent.provider,
          integrationStatus: integration.status,
          statusReason: integration.statusReason,
        });
        return {
          allowed: false as const,
          reason: "inactive_connection" as const,
        };
      }

      const baseEventType = getBaseEventType(
        sourceEvent.provider,
        sourceEvent.eventType
      );
      const allowed = isEventAllowed(integration.providerConfig, baseEventType);

      if (!allowed) {
        log.info("[event-store] event filtered by provider config", {
          clerkOrgId,
          resourceId,
          eventType: sourceEvent.eventType,
          baseEventType,
          configuredEvents: integration.providerConfig?.sync?.events,
        });
      }

      return {
        allowed,
        reason: allowed ? ("allowed" as const) : ("event_not_allowed" as const),
      };
    });

    if (!gateResult.allowed) {
      const filteredReason =
        gateResult.reason === "inactive_connection"
          ? ("inactive_connection" as const)
          : ("event_not_allowed" as const);

      await step.run("complete-job-filtered", async () => {
        await completeJob({
          jobId,
          status: "completed",
          output: {
            inngestFunctionId: "event.capture",
            status: "filtered",
            reason: filteredReason,
            sourceId: sourceEvent.sourceId,
          } satisfies EventCaptureOutputFiltered,
        });
      });

      return {
        status: "filtered",
        reason:
          filteredReason === "inactive_connection"
            ? "Integration is not active"
            : "Event type not enabled in source config",
        duration: Date.now() - startTime,
      };
    }

    // Step 3: Evaluate significance (metadata annotation, not a gate)
    const significance = await step.run("evaluate-significance", () => {
      return scoreSignificance(sourceEvent);
    });

    // Step 4: Extract entities (structural categories from relations)
    const extractedEntities = await step.run("extract-entities", () => {
      const textEntities = extractEntities(sourceEvent.title, sourceEvent.body);
      const refEntities = extractFromRelations(sourceEvent.relations);

      // Primary entity from sourceEvent.entity — always upserted with highest
      // confidence so entity-embed can always find it by (clerkOrgId, category, key).
      // value is undefined so refLabel on the junction row stays null (it has no
      // relationship-type label — it IS the event's primary subject).
      const primaryEntityExtracted: ExtractedEntity = {
        category: sourceEvent.entity.entityType as EntityCategory,
        key: sourceEvent.entity.entityId,
        value: undefined,
        confidence: 1.0,
        evidence: `Primary entity: ${sourceEvent.entity.entityType}`,
        state: sourceEvent.entity.state ?? undefined,
        url: sourceEvent.entity.url ?? undefined,
      };

      // Primary entity first — Map insertion order preserved, so it is always
      // at index 0 of deduplicated (used to retrieve externalId after upsert).
      const allEntities = [
        primaryEntityExtracted,
        ...textEntities,
        ...refEntities,
      ];
      const entityMap = new Map<string, ExtractedEntity>();

      for (const entity of allEntities) {
        const key = `${entity.category}:${entity.key.toLowerCase()}`;
        const existingEntity = entityMap.get(key);
        if (!existingEntity || existingEntity.confidence < entity.confidence) {
          entityMap.set(key, entity);
        }
      }

      const deduplicated = Array.from(entityMap.values());
      return deduplicated.slice(0, 50); // MAX_ENTITIES_PER_OBSERVATION
    });

    // Step 5: Store observation row
    const observation = await step.run("store-observation", async () => {
      const observationType = deriveObservationType(
        sourceEvent.provider,
        sourceEvent.eventType
      );

      const [obs] = await db
        .insert(orgEvents)
        .values({
          externalId,
          clerkOrgId,
          occurredAt: sourceEvent.occurredAt,
          observationType,
          title: sourceEvent.title,
          content: sourceEvent.body,
          source: sourceEvent.provider,
          sourceType: sourceEvent.eventType,
          sourceId: sourceEvent.sourceId,
          sourceReferences: sourceEvent.relations,
          metadata: sourceEvent.attributes,
          ingestionSource: event.data.ingestionSource ?? "webhook",
          ingestLogId: ingestLogId ?? null,
          significanceScore: significance.score,
        })
        .returning();

      if (!obs) {
        throw new NonRetriableError("Failed to insert observation");
      }

      log.info("[event-store] observation stored", {
        observationId: obs.id,
        externalId: obs.externalId,
        observationType,
        ingestLogId,
        correlationId,
      });

      return obs;
    });

    // Step 6: Upsert entities and create junction rows
    const entityUpsertResult = await step.run(
      "upsert-entities-and-junctions",
      async () => {
        if (extractedEntities.length === 0) {
          return { count: 0, primaryEntityExternalId: null as string | null };
        }

        // Upsert each entity and get back its ID + externalId for junction inserts.
        // externalId is needed to emit entity.upserted with the stable Pinecone vector key.
        const entityResults = await Promise.all(
          extractedEntities.map((entity) =>
            db
              .insert(orgEntities)
              .values({
                clerkOrgId,
                category: entity.category,
                key: entity.key,
                value: entity.value,
                evidenceSnippet: entity.evidence,
                confidence: entity.confidence,
                state: entity.state ?? null,
                url: entity.url ?? null,
              })
              .onConflictDoUpdate({
                target: [
                  orgEntities.clerkOrgId,
                  orgEntities.category,
                  orgEntities.key,
                ],
                set: {
                  lastSeenAt: sql`GREATEST(${orgEntities.lastSeenAt}, excluded.${sql.identifier(orgEntities.lastSeenAt.name)})`,
                  occurrenceCount: sql`${orgEntities.occurrenceCount} + 1`,
                  updatedAt: new Date().toISOString(),
                  state: sql`CASE WHEN excluded.${sql.identifier(orgEntities.lastSeenAt.name)} > ${orgEntities.lastSeenAt} THEN excluded.${sql.identifier(orgEntities.state.name)} ELSE ${orgEntities.state} END`,
                  url: sql`COALESCE(excluded.${sql.identifier(orgEntities.url.name)}, ${orgEntities.url})`,
                },
              })
              .returning({
                id: orgEntities.id,
                externalId: orgEntities.externalId,
              })
          )
        );

        // Primary entity is always at index 0 (inserted first in extractedEntities,
        // Map insertion order preserved, and confidence 1.0 ensures it wins dedup).
        const primaryEntityExternalId =
          entityResults[0]?.[0]?.externalId ?? null;

        // Create junction rows mapping entities to this observation
        const junctionRows = entityResults
          .map((result, i) => {
            const entityId = result[0]?.id;
            if (entityId === undefined) {
              return null;
            }
            const entity = extractedEntities[i]!;
            return {
              entityId,
              eventId: observation.id,
              clerkOrgId,
              category: entity.category,
              // Only structural ref entities carry a contextual relationship label.
              // The primary entity (index 0) has value=undefined -> refLabel=null.
              refLabel: STRUCTURAL_TYPES.has(entity.category)
                ? (entity.value ?? null)
                : null,
            };
          })
          .filter((row): row is NonNullable<typeof row> => row !== null);

        if (junctionRows.length > 0) {
          await db
            .insert(orgEventEntities)
            .values(junctionRows)
            .onConflictDoNothing();
        }

        log.info("[event-store] entities and junctions stored", {
          observationId: observation.id,
          entitiesStored: junctionRows.length,
          ingestLogId,
          correlationId,
        });

        return { count: junctionRows.length, primaryEntityExternalId };
      }
    );

    // Build entity refs for entity-graph downstream step.
    const entityRefs = [
      {
        type: sourceEvent.entity.entityType,
        key: sourceEvent.entity.entityId,
        label: null,
      },
      ...sourceEvent.relations.map((rel) => ({
        type: rel.entityType,
        key: rel.entityId,
        label: rel.relationshipType,
      })),
    ];

    // Step 7: Emit entity.upserted (triggers entity-graph -> entity-embed chain)
    if (entityUpsertResult.primaryEntityExternalId) {
      await step.sendEvent("emit-downstream-events", {
        name: "platform/entity.upserted" as const,
        data: {
          clerkOrgId,
          entityExternalId: entityUpsertResult.primaryEntityExternalId,
          entityType: sourceEvent.entity.entityType,
          provider: sourceEvent.provider,
          internalEventId: observation.id,
          entityRefs,
          occurredAt: sourceEvent.occurredAt,
          correlationId,
        },
      });
    }

    // Step 7b: Emit event.stored (triggers notification dispatch)
    await step.sendEvent("emit-event-stored", {
      name: "platform/event.stored" as const,
      data: {
        clerkOrgId,
        eventExternalId: observation.externalId,
        sourceType: sourceEvent.eventType,
        significanceScore: significance.score,
        correlationId,
      },
    });

    // Step 8: Complete job with success output
    const finalDuration = Date.now() - startTime;
    await step.run("complete-job-success", async () => {
      await completeJob({
        jobId,
        status: "completed",
        output: {
          inngestFunctionId: "event.capture",
          status: "success",
          observationId: observation.externalId,
          observationType: observation.observationType,
          significanceScore: significance.score,
          entitiesExtracted: entityUpsertResult.count,
        } satisfies EventCaptureOutputSuccess,
      });
    });

    return {
      status: "stored",
      observationId: observation.externalId,
      observationType: observation.observationType,
      duration: finalDuration,
    };
  }
);

/**
 * Entity graph workflow
 *
 * Subscribes to entity.upserted, resolves entity<->entity edges via the
 * co-occurrence algorithm, then emits entity.graphed so entity-embed can
 * build its narrative with up-to-date graph context.
 *
 * Extracted from event-interpret.ts — graph resolution has no LLM dependency
 * and should not be blocked by classification latency.
 */

import { log } from "@vendor/observability/log/next";
import { resolveEdges } from "../../lib/edge-resolver";
import { inngest } from "../client";
import { createNeuralOnFailureHandler } from "../on-failure-handler";

export const platformEntityGraph = inngest.createFunction(
  {
    id: "platform/entity.graph",
    name: "Entity Graph",
    description: "Resolves entity edges after upsert (fast, pure SQL)",
    retries: 3,
    timeouts: { finish: "2m" },
    onFailure: createNeuralOnFailureHandler("platform/entity.upserted"),
  },
  { event: "platform/entity.upserted" },
  async ({ event, step }) => {
    const { clerkOrgId, internalEventId, provider, entityRefs, correlationId } =
      event.data;

    const edgeCount = await step.run("resolve-edges", () =>
      resolveEdges(clerkOrgId, internalEventId, provider, entityRefs)
    );

    log.info("[entity-graph] edges resolved", {
      clerkOrgId,
      internalEventId,
      provider,
      entityExternalId: event.data.entityExternalId,
      edgeCount,
      correlationId,
    });

    await step.sendEvent("emit-entity-graphed", {
      name: "platform/entity.graphed" as const,
      data: {
        clerkOrgId,
        entityExternalId: event.data.entityExternalId,
        entityType: event.data.entityType,
        provider,
        occurredAt: event.data.occurredAt,
        correlationId,
      },
    });

    return { edgeCount };
  }
);

/**
 * Entity embed workflow
 *
 * Subscribes to entity.graphed (NOT entity.upserted) so that graph edges are
 * committed before the narrative is built. This avoids the race condition where
 * concurrent entity-embed and entity-graph functions both start from the same
 * entity.upserted event and entity-embed reads stale edges.
 *
 * Debounced per entity: burst events collapse into a single embed call.
 */

import { buildOrgNamespace } from "@db/app";
import { db } from "@db/app/client";
import {
  orgEntities,
  orgEntityEdges,
  orgEventEntities,
  orgEvents,
} from "@db/app/schema";
import type { EntityVectorMetadata } from "@repo/app-validation";
import { EMBEDDING_DEFAULTS } from "@repo/app-validation";
import { NonRetriableError } from "@vendor/inngest";
import { log } from "@vendor/observability/log/next";
import { asc, desc, eq, sql } from "drizzle-orm";
import {
  buildEntityNarrative,
  narrativeHash,
} from "../../lib/narrative-builder";
import { inngest } from "../client";
import { createNeuralOnFailureHandler } from "../on-failure-handler";

/**
 * Hard character cap applied to the narrative before embedding.
 *
 * Cohere embed-english-v3.0 has a 512-token context window. English text
 * averages ~4 chars/token, so 512 tokens ~ 2,048 chars. We cap at 1,800
 * (~ 450 tokens) to leave a 62-token safety buffer and accommodate any
 * non-English content in entity keys or values.
 *
 * The narrative sections are ordered most-important-first (identity ->
 * genesis -> temporal span -> recent events -> graph edges), so if the cap
 * ever fires, it discards from the least-important tail.
 *
 * @see vendor/embed/src/provider/cohere.ts — truncate: "NONE" will surface
 * an error if this cap fails to hold (e.g. a very long entity.value in
 * Section 1).
 */
const NARRATIVE_CHAR_CAP = 1800;

export const platformEntityEmbed = inngest.createFunction(
  {
    id: "platform/entity.embed",
    name: "Entity Embed",
    description:
      "Builds entity narrative and upserts to Pinecone (layer=entities)",
    debounce: {
      // Collapse burst events for the same entity into one embed call
      key: "event.data.entityExternalId",
      period: "30s",
    },
    retries: 3,
    timeouts: { finish: "2m" },
    onFailure: createNeuralOnFailureHandler("platform/entity.graphed"),
  },
  { event: "platform/entity.graphed" },
  async ({ event, step }) => {
    const { clerkOrgId, entityExternalId, provider, correlationId } =
      event.data;

    log.info("[entity-embed] starting", {
      clerkOrgId,
      entityExternalId,
      provider,
      correlationId,
    });

    // Step 1: Fetch all narrative inputs in a single step.
    // Throws NonRetriableError for missing rows so Inngest does not retry infinitely.
    const entity = await step.run("fetch-entity", async () => {
      const row = await db.query.orgEntities.findFirst({
        where: eq(orgEntities.externalId, entityExternalId),
        columns: {
          id: true,
          externalId: true,
          category: true,
          key: true,
          value: true,
          extractedAt: true,
          lastSeenAt: true,
          occurrenceCount: true,
        },
      });
      if (!row) {
        log.warn("[entity-embed] entity not found, aborting", {
          entityExternalId,
          correlationId,
        });
        throw new NonRetriableError(`Entity not found: ${entityExternalId}`);
      }
      return row;
    });

    const [genesisResults, recentEvents, edges, maxSignificanceResults] =
      await step.run("fetch-narrative-inputs", async () => {
        return Promise.all([
          // Genesis event (first ever — founding context, never lost)
          db
            .select({
              title: orgEvents.title,
              sourceType: orgEvents.sourceType,
              occurredAt: orgEvents.occurredAt,
            })
            .from(orgEventEntities)
            .innerJoin(orgEvents, eq(orgEventEntities.eventId, orgEvents.id))
            .where(eq(orgEventEntities.entityId, entity.id))
            .orderBy(asc(orgEvents.occurredAt))
            .limit(1),

          // Last 3 events (recency signal + current state)
          db
            .select({
              title: orgEvents.title,
              sourceType: orgEvents.sourceType,
              occurredAt: orgEvents.occurredAt,
            })
            .from(orgEventEntities)
            .innerJoin(orgEvents, eq(orgEventEntities.eventId, orgEvents.id))
            .where(eq(orgEventEntities.entityId, entity.id))
            .orderBy(desc(orgEvents.occurredAt))
            .limit(3),

          // Graph edges — both outgoing and incoming, mapped to "related entity".
          // LIMIT 3 per direction: each edge line is ~180 chars / ~45 tokens.
          // See NARRATIVE_CHAR_CAP for the full token budget reasoning.
          db
            .select({
              relationshipType: orgEntityEdges.relationshipType,
              targetCategory: orgEntities.category,
              targetKey: orgEntities.key,
            })
            .from(orgEntityEdges)
            .innerJoin(
              orgEntities,
              eq(orgEntityEdges.targetEntityId, orgEntities.id)
            )
            .where(eq(orgEntityEdges.sourceEntityId, entity.id))
            .limit(3)
            .union(
              db
                .select({
                  relationshipType: orgEntityEdges.relationshipType,
                  targetCategory: orgEntities.category,
                  targetKey: orgEntities.key,
                })
                .from(orgEntityEdges)
                .innerJoin(
                  orgEntities,
                  eq(orgEntityEdges.sourceEntityId, orgEntities.id)
                )
                .where(eq(orgEntityEdges.targetEntityId, entity.id))
                .limit(3)
            ),

          // Max significance score across all events for this entity
          db
            .select({
              max: sql<number>`MAX(${orgEvents.significanceScore})`,
            })
            .from(orgEventEntities)
            .innerJoin(orgEvents, eq(orgEventEntities.eventId, orgEvents.id))
            .where(eq(orgEventEntities.entityId, entity.id)),
        ]);
      });

    const genesisEvent = genesisResults[0] ?? null;
    const maxSignificanceScore = maxSignificanceResults[0]?.max ?? 0;

    // Build narrative text and hash outside of a step (CPU-only, no I/O)
    const narrative = buildEntityNarrative(
      entity,
      genesisEvent,
      recentEvents,
      edges
    );
    const hash = narrativeHash(narrative);
    const latestEvent = recentEvents[0];

    // Cap the narrative to NARRATIVE_CHAR_CAP characters before embedding.
    // Sections are ordered most-important-first; the cap discards from the tail.
    // truncate: "NONE" in the Cohere provider will surface an error if this cap
    // ever fails to hold (e.g. an unusually long entity.value in Section 1).
    const cappedNarrative = narrative.slice(0, NARRATIVE_CHAR_CAP);
    if (narrative.length > NARRATIVE_CHAR_CAP) {
      log.warn("[entity-embed] narrative capped", {
        entityExternalId,
        original: narrative.length,
        cap: NARRATIVE_CHAR_CAP,
        correlationId,
      });
    }

    // Step 2: Embed the narrative using constants
    const embedding = await step.run("embed-narrative", async () => {
      const { createEmbeddingProviderForOrg } = await import("@repo/app-embed");
      const embeddingProvider = createEmbeddingProviderForOrg(
        {
          id: clerkOrgId,
          embeddingModel: EMBEDDING_DEFAULTS.embeddingModel,
          embeddingDim: EMBEDDING_DEFAULTS.embeddingDim,
        },
        { inputType: "search_document" }
      );

      const { embeddings } = await embeddingProvider.embed([cappedNarrative]);
      const vector = embeddings[0];
      if (!vector) {
        log.error("[entity-embed] embedding provider returned no vector", {
          entityExternalId,
          correlationId,
        });
        throw new Error("Embedding provider returned no vector");
      }
      return vector;
    });

    // Step 3: UPSERT single entity vector to Pinecone
    await step.run("upsert-entity-vector", async () => {
      const { lightfastPineconeClient } = await import("@repo/app-pinecone");
      const indexName = EMBEDDING_DEFAULTS.indexName;
      const namespaceName = buildOrgNamespace(clerkOrgId);

      const metadata: EntityVectorMetadata = {
        layer: "entities",
        entityExternalId: entity.externalId,
        entityType: entity.category,
        provider,
        latestAction: latestEvent?.sourceType.split(".").pop() ?? "",
        title: narrative.split("\n")[0] ?? entity.key,
        snippet: narrative.slice(0, 500),
        // Unix ms timestamps — numeric for reliable Pinecone range filters
        occurredAt: latestEvent
          ? new Date(latestEvent.occurredAt).getTime()
          : Date.now(),
        createdAt: new Date(entity.extractedAt).getTime(),
        narrativeHash: hash,
        totalEvents: entity.occurrenceCount,
        significanceScore: maxSignificanceScore,
      };

      await lightfastPineconeClient.upsertVectors<EntityVectorMetadata>(
        indexName,
        {
          ids: [`ent_${entity.externalId}`],
          vectors: [embedding],
          metadata: [metadata],
        },
        namespaceName
      );

      log.info("[entity-embed] entity vector upserted", {
        entityExternalId: entity.externalId,
        entityType: entity.category,
        vectorId: `ent_${entity.externalId}`,
        totalEvents: entity.occurrenceCount,
        edgeCount: edges.length,
        narrativeHash: hash,
        correlationId,
      });
    });

    return {
      entityExternalId: entity.externalId,
      narrativeHash: hash,
      totalEvents: entity.occurrenceCount,
      edgeCount: edges.length,
    };
  }
);

