1	/**
2	 * Platform backfill orchestrator
3	 *
4	 * Ported from apps/backfill/src/workflows/backfill-orchestrator.ts
5	 *
6	 * KEY CHANGES vs backfill service:
7	 * - Function ID: platform/backfill.orchestrator (was backfill/run.orchestrator)
8	 * - Trigger: platform/backfill.run.requested (was backfill/run.requested)
9	 * - cancelOn: platform/backfill.run.cancelled (was backfill/run.cancelled)
10	 * - Replace createGatewayClient() HTTP calls with direct DB queries
11	 * - Replace relay.replayCatchup() with direct DB query + inngest.send("platform/webhook.received")
12	 * - step.invoke() references platformEntityWorker
13	 */
14	
15	import { db } from "@db/app/client";
16	import {
17	  gatewayBackfillRuns,
18	  gatewayInstallations,
19	  gatewayWebhookDeliveries,
20	  orgIntegrations,
21	} from "@db/app/schema";
22	import { getProvider, type ProviderDefinition } from "@repo/app-providers";
23	import { and, eq, inArray, notInArray } from "@vendor/db";
24	import { NonRetriableError } from "@vendor/inngest";
25	import { parseError } from "@vendor/observability/error/next";
26	import { log } from "@vendor/observability/log/next";
27	import { providerConfigs } from "../../lib/provider-configs";
28	import { getActiveTokenForInstallation } from "../../lib/token-helpers";
29	import { inngest } from "../client";
30	import { platformEntityWorker } from "./platform-entity-worker";
31	
32	export const platformBackfillOrchestrator = inngest.createFunction(
33	  {
34	    id: "platform/backfill.orchestrator",
35	    name: "Platform Backfill Orchestrator",
36	    retries: 3,
37	    concurrency: [
38	      // 1 backfill per connection — prevents duplicate backfills
39	      { limit: 1, key: "event.data.installationId" },
40	      // 10 total concurrent orchestrators (each lightweight — just fan-out + wait)
41	      { limit: 10 },
42	    ],
43	    cancelOn: [
44	      {
45	        event: "platform/backfill.run.cancelled",
46	        match: "data.installationId",
47	      },
48	    ],
49	    // Orchestrator waits for all entity workers — must accommodate the longest
50	    // Worst case: 15 work units (5 repos x 3 entities), 5 concurrent, each 2hr
51	    // = 15/5 * 2hr = 6hr total. Set to 8hr for safety.
52	    timeouts: { start: "2m", finish: "8h" },
53	  },
54	  { event: "platform/backfill.run.requested" },
55	  async ({ event, step }) => {
56	    const {
57	      installationId,
58	      provider,
59	      orgId,
60	      depth,
61	      entityTypes,
62	      holdForReplay,
63	      correlationId,
64	    } = event.data;
65	
66	    log.info("[backfill-orchestrator] starting", {
67	      installationId,
68	      provider,
69	      depth,
70	      entityTypes,
71	      correlationId,
72	    });
73	
74	    if (depth <= 0) {
75	      throw new NonRetriableError(
76	        `Invalid depth: ${depth} — must be a positive number of days`
77	      );
78	    }
79	
80	    // ── Step 1: Fetch connection details from DB (replaces gateway HTTP call) ──
81	    const connection = await step.run("get-connection", async () => {
82	      const installationRows = await db
83	        .select()
84	        .from(gatewayInstallations)
85	        .where(eq(gatewayInstallations.id, installationId))
86	        .limit(1);
87	
88	      const conn = installationRows[0];
89	      if (!conn) {
90	        throw new NonRetriableError(`Connection not found: ${installationId}`);
91	      }
92	      if (conn.status !== "active") {
93	        throw new NonRetriableError(
94	          `Connection is not active: ${installationId} (status: ${conn.status})`
95	        );
96	      }
97	      // Tenant isolation: verify caller-supplied orgId matches the DB-canonical value
98	      if (conn.orgId !== orgId) {
99	        throw new NonRetriableError(
100	          `orgId mismatch: event has "${orgId}" but connection belongs to "${conn.orgId}"`
101	        );
102	      }
103	
104	      // Fetch linked resources from orgIntegrations
105	      const resources = await db
106	        .select({
107	          providerResourceId: orgIntegrations.providerResourceId,
108	        })
109	        .from(orgIntegrations)
110	        .where(
111	          and(
112	            eq(orgIntegrations.installationId, installationId),
113	            eq(orgIntegrations.status, "active")
114	          )
115	        );
116	
117	      return {
118	        id: conn.id,
119	        externalId: conn.externalId,
120	        provider: conn.provider,
121	        orgId: conn.orgId,
122	        status: conn.status,
123	        resources,
124	      };
125	    });
126	
127	    log.info("[backfill-orchestrator] connection fetched", {
128	      installationId,
129	      provider,
130	      resourceCount: connection.resources.length,
131	      correlationId,
132	    });
133	
134	    // ── Step 1b: Fetch backfill history from DB (replaces gateway HTTP call) ──
135	    const backfillHistory = await step.run("get-backfill-history", async () => {
136	      return db
137	        .select({
138	          entityType: gatewayBackfillRuns.entityType,
139	          providerResourceId: gatewayBackfillRuns.providerResourceId,
140	          since: gatewayBackfillRuns.since,
141	        })
142	        .from(gatewayBackfillRuns)
143	        .where(
144	          and(
145	            eq(gatewayBackfillRuns.installationId, installationId),
146	            eq(gatewayBackfillRuns.status, "completed")
147	          )
148	        );
149	    });
150	
151	    // ── Step 2: Resolve entity types and validate provider ──
152	    const providerDef = getProvider(provider);
153	    if (!providerDef) {
154	      throw new NonRetriableError(
155	        `No backfill provider for provider: ${provider}`
156	      );
157	    }
158	    if (!providerDef.backfill) {
159	      throw new NonRetriableError(
160	        `Provider "${provider}" does not support backfill`
161	      );
162	    }
163	
164	    const resolvedEntityTypes =
165	      entityTypes && entityTypes.length > 0
166	        ? entityTypes
167	        : [...providerDef.backfill.defaultEntityTypes];
168	
169	    // Compute `since` inside a step so it's deterministic across retries/replays
170	    const since = await step.run("compute-since", () =>
171	      new Date(Date.now() - depth * 24 * 60 * 60 * 1000).toISOString()
172	    );
173	
174	    // ── Step 2b: Resolve resource names live from provider API ──
175	    const resolvedResources = await step.run(
176	      "resolve-resource-meta",
177	      async () => {
178	        const config = providerConfigs[provider];
179	        const { token } = await getActiveTokenForInstallation(
180	          {
181	            id: connection.id,
182	            externalId: connection.externalId,
183	            provider: connection.provider,
184	          },
185	          config,
186	          providerDef as ProviderDefinition
187	        );
188	
189	        // Providers where resourceName is NOT needed for API routing can fall back
190	        const resourceNameRequiredForRouting = ["github", "sentry"].includes(
191	          provider
192	        );
193	
194	        return Promise.all(
195	          connection.resources.map(async (r) => {
196	            try {
197	              const resourceName =
198	                await providerDef.backfill!.resolveResourceMeta({
199	                  providerResourceId: r.providerResourceId,
200	                  token,
201	                });
202	              return { providerResourceId: r.providerResourceId, resourceName };
203	            } catch (err) {
204	              log.warn("[backfill] failed to resolve resource meta", {
205	                providerResourceId: r.providerResourceId,
206	                error: parseError(err),
207	              });
208	              if (resourceNameRequiredForRouting) {
209	                // GitHub/Sentry: resourceName is used in buildRequest pathParams — must skip
210	                return null;
211	              }
212	              // Linear/Vercel: resourceName is only used in adapter output — fallback is safe
213	              return {
214	                providerResourceId: r.providerResourceId,
215	                resourceName: r.providerResourceId,
216	              };
217	            }
218	          })
219	        ).then((results) =>
220	          results.filter((r): r is NonNullable<typeof r> => r !== null)
221	        );
222	      }
223	    );
224	
225	    // ── Step 3: Enumerate work units (resource x entityType) ──
226	    const workUnits = resolvedResources.flatMap((resource) => {
227	      return resolvedEntityTypes.map((entityType: string) => ({
228	        entityType,
229	        resource: {
230	          providerResourceId: resource.providerResourceId,
231	          resourceName: resource.resourceName,
232	        },
233	        workUnitId: `${resource.providerResourceId}-${entityType}`,
234	      }));
235	    });
236	
237	    // ── Gap-aware filtering: skip (resource, entityType) pairs covered by prior runs ──
238	    const filteredWorkUnits = workUnits.filter((wu) => {
239	      const priorRun = backfillHistory.find(
240	        (h) =>
241	          h.entityType === wu.entityType &&
242	          h.providerResourceId === wu.resource.providerResourceId
243	      );
244	      if (!priorRun) {
245	        return true; // No prior run — must fetch
246	      }
247	      // Prior run's since ≤ requested since → already covered
248	      return new Date(priorRun.since) > new Date(since);
249	    });
250	
251	    log.info("[backfill-orchestrator] work units planned", {
252	      installationId,
253	      provider,
254	      total: workUnits.length,
255	      afterFilter: filteredWorkUnits.length,
256	      skippedByGapFilter: workUnits.length - filteredWorkUnits.length,
257	      since,
258	      correlationId,
259	    });
260	
261	    if (filteredWorkUnits.length === 0) {
262	      return {
263	        success: true,
264	        installationId,
265	        provider,
266	        workUnits: workUnits.length,
267	        skipped: workUnits.length,
268	        dispatched: 0,
269	        eventsProduced: 0,
270	        eventsDispatched: 0,
271	      };
272	    }
273	
274	    log.info("[backfill-orchestrator] dispatching entity workers", {
275	      installationId,
276	      provider,
277	      count: filteredWorkUnits.length,
278	      workUnitIds: filteredWorkUnits.map((wu) => wu.workUnitId),
279	      correlationId,
280	    });
281	
282	    // ── Step 4: Invoke entity workers directly ──
283	    const completionResults = await Promise.all(
284	      filteredWorkUnits.map(async (wu) => {
285	        try {
286	          const result = await step.invoke(`invoke-${wu.workUnitId}`, {
287	            function: platformEntityWorker,
288	            data: {
289	              installationId,
290	              provider,
291	              orgId,
292	              entityType: wu.entityType,
293	              resource: wu.resource,
294	              since,
295	              depth,
296	              holdForReplay,
297	              correlationId,
298	            },
299	            timeout: "4h",
300	          });
301	          return {
302	            entityType: wu.entityType,
303	            resourceId: wu.resource.providerResourceId,
304	            success: true,
305	            eventsProduced: result.eventsProduced,
306	            eventsDispatched: result.eventsDispatched,
307	            pagesProcessed: result.pagesProcessed,
308	          };
309	        } catch (err) {
310	          return {
311	            entityType: wu.entityType,
312	            resourceId: wu.resource.providerResourceId,
313	            success: false,
314	            eventsProduced: 0,
315	            eventsDispatched: 0,
316	            pagesProcessed: 0,
317	            error: parseError(err),
318	          };
319	        }
320	      })
321	    );
322	
323	    // ── Step 5: Aggregate results ──
324	    const succeeded = completionResults.filter((r) => r.success);
325	    const failed = completionResults.filter((r) => !r.success);
326	
327	    // ── Step 6: Persist run records — one per (resource, entityType) ──
328	    if (completionResults.length > 0) {
329	      await step.run("persist-run-records", async () => {
330	        const now = new Date().toISOString();
331	        for (const r of completionResults) {
332	          const sharedFields = {
333	            since,
334	            depth,
335	            status: r.success ? "completed" : "failed",
336	            pagesProcessed: r.pagesProcessed,
337	            eventsProduced: r.eventsProduced,
338	            eventsDispatched: r.eventsDispatched,
339	            error: r.success ? null : (r.error ?? null),
340	            completedAt: now,
341	            updatedAt: now,
342	          };
343	
344	          await db
345	            .insert(gatewayBackfillRuns)
346	            .values({
347	              installationId,
348	              entityType: r.entityType,
349	              providerResourceId: r.resourceId,
350	              ...sharedFields,
351	              startedAt: now,
352	            })
353	            .onConflictDoUpdate({
354	              target: [
355	                gatewayBackfillRuns.installationId,
356	                gatewayBackfillRuns.providerResourceId,
357	                gatewayBackfillRuns.entityType,
358	              ],
359	              set: sharedFields,
360	            });
361	        }
362	      });
363	    }
364	
365	    // ── Step 7: Replay held webhooks (replaces relay.replayCatchup) ──
366	    // When holdForReplay is set, entity workers persist webhooks without delivery.
367	    // After all workers complete, drain them by querying DB directly and sending
368	    // platform/webhook.received events so they are processed in chronological order.
369	    if (holdForReplay && succeeded.length > 0) {
370	      log.info("[backfill-orchestrator] replaying held webhooks", {
371	        installationId,
372	        succeededWorkers: succeeded.length,
373	        correlationId,
374	      });
375	      await step.run("replay-held-webhooks", async () => {
376	        const BATCH_SIZE = 200;
377	        const MAX_ITERATIONS = 500; // Safety cap: 500 * 200 = 100k webhooks max
378	        let iterations = 0;
379	        const processedIds: string[] = [];
380	
381	        while (iterations < MAX_ITERATIONS) {
382	          iterations++;
383	
384	          // Query un-delivered webhooks for this installation
385	          const conditions = [
386	            eq(gatewayWebhookDeliveries.installationId, installationId),
387	            eq(gatewayWebhookDeliveries.status, "held"),
388	          ];
389	          if (processedIds.length > 0) {
390	            conditions.push(
391	              notInArray(gatewayWebhookDeliveries.id, processedIds)
392	            );
393	          }
394	
395	          const deliveries = await db
396	            .select()
397	            .from(gatewayWebhookDeliveries)
398	            .where(and(...conditions))
399	            .orderBy(gatewayWebhookDeliveries.receivedAt)
400	            .limit(BATCH_SIZE);
401	
402	          if (deliveries.length === 0) {
403	            break;
404	          }
405	
406	          // Send each delivery as a platform/webhook.received event
407	          const events = deliveries
408	            .filter((d) => d.payload)
409	            .map((d) => ({
410	              name: "platform/webhook.received" as const,
411	              data: {
412	                provider: d.provider,
413	                deliveryId: d.deliveryId,
414	                eventType: d.eventType,
415	                resourceId: null as string | null,
416	                payload: JSON.parse(d.payload!) as unknown,
417	                receivedAt: new Date(d.receivedAt).getTime(),
418	                preResolved: {
419	                  connectionId: installationId,
420	                  orgId: connection.orgId,
421	                },
422	                correlationId,
423	              },
424	            }));
425	
426	          if (events.length > 0) {
427	            await inngest.send(events);
428	          }
429	
430	          // Mark replayed deliveries so they aren't re-sent on retry (held -> enqueued)
431	          const replayedIds = deliveries.map((d) => d.id);
432	          if (replayedIds.length > 0) {
433	            await db
434	              .update(gatewayWebhookDeliveries)
435	              .set({ status: "enqueued" })
436	              .where(
437	                and(
438	                  eq(gatewayWebhookDeliveries.installationId, installationId),
439	                  inArray(gatewayWebhookDeliveries.id, replayedIds)
440	                )
441	              );
442	          }
443	
444	          // Track processed IDs to exclude from next batch
445	          for (const d of deliveries) {
446	            processedIds.push(d.id);
447	          }
448	        }
449	
