1	/**
2	 * Connection lifecycle (teardown) function
3	 *
4	 * Ported from apps/gateway/src/workflows/connection-teardown.ts
5	 *
6	 * KEY CHANGES vs gateway service:
7	 * - Upstash Workflow context.run() → Inngest step.run()
8	 * - Function ID: platform/connection.lifecycle
9	 * - Trigger: platform/connection.lifecycle event (was Upstash Workflow trigger)
10	 * - Cancel backfill: fires Inngest event instead of QStash publish
11	 * - All 5 steps preserved: close-gate, cancel-backfill, revoke-token, cleanup-cache, remove-resources
12	 */
13	
14	import { db } from "@db/app/client";
15	import {
16	  gatewayInstallations,
17	  gatewayLifecycleLogs,
18	  gatewayTokens,
19	  orgIntegrations,
20	} from "@db/app/schema";
21	import type { SourceType } from "@repo/app-providers";
22	import { getProvider } from "@repo/app-providers";
23	import { decrypt } from "@repo/lib";
24	import { eq } from "@vendor/db";
25	import { parseError } from "@vendor/observability/error/next";
26	import { log } from "@vendor/observability/log/next";
27	import { getEncryptionKey } from "../../lib/encryption";
28	import { providerConfigs } from "../../lib/provider-configs";
29	import { inngest } from "../client";
30	
31	export const connectionLifecycle = inngest.createFunction(
32	  {
33	    id: "platform/connection.lifecycle",
34	    name: "Connection Lifecycle (Teardown)",
35	    retries: 3,
36	    concurrency: [
37	      // 1 teardown per connection at a time
38	      { limit: 1, key: "event.data.installationId" },
39	    ],
40	    timeouts: { start: "1m", finish: "5m" },
41	  },
42	  { event: "platform/connection.lifecycle" },
43	  async ({ event, step }) => {
44	    const {
45	      installationId,
46	      provider: providerName,
47	      correlationId,
48	    } = event.data;
49	
50	    log.info("[connection-lifecycle] starting", {
51	      installationId,
52	      provider: providerName,
53	    });
54	
55	    // Step 1: Close the ingress gate — all guards check status === 'active',
56	    // so setting 'revoked' immediately blocks new requests.
57	    await step.run("close-gate", async () => {
58	      await db
59	        .update(gatewayInstallations)
60	        .set({ status: "revoked", updatedAt: new Date().toISOString() })
61	        .where(eq(gatewayInstallations.id, installationId));
62	
63	      await db.insert(gatewayLifecycleLogs).values({
64	        installationId,
65	        event: "gate_closed",
66	        fromStatus: "active",
67	        toStatus: "revoked",
68	        reason: "Ingress gate closed by teardown workflow",
69	        metadata: {
70	          step: "close-gate",
71	          workflowContext: "connection-lifecycle",
72	          triggeredBy: "system",
73	        },
74	      });
75	
76	      log.info("[connection-lifecycle] gate closed", { installationId });
77	    });
78	
79	    // Step 2: Cancel any running backfill (best-effort, via Inngest event)
80	    await step.run("cancel-backfill", async () => {
81	      try {
82	        await inngest.send({
83	          name: "platform/backfill.run.cancelled",
84	          data: {
85	            installationId,
86	            correlationId,
87	          },
88	        });
89	        log.info("[connection-lifecycle] backfill cancellation sent", {
90	          installationId,
91	        });
92	      } catch (err) {
93	        log.warn(
94	          "[connection-lifecycle] backfill cancellation failed (best-effort)",
95	          {
96	            installationId,
97	            error: parseError(err),
98	          }
99	        );
100	      }
101	    });
102	
103	    // Step 3: Revoke token at provider (best-effort)
104	    await step.run("revoke-token", async () => {
105	      if (providerName === "github") {
106	        log.info(
107	          "[connection-lifecycle] skipping token revocation (github uses on-demand JWTs)",
108	          {
109	            installationId,
110	          }
111	        );
112	        return;
113	      }
114	
115	      const providerDef = getProvider(providerName as SourceType);
116	      const config = providerConfigs[providerName];
117	
118	      if (!config) {
119	        log.warn(
120	          "[connection-lifecycle] provider not configured, skipping token revocation",
121	          {
122	            installationId,
123	            provider: providerName,
124	          }
125	        );
126	        return;
127	      }
128	
129	      const tokenRows = await db
130	        .select()
131	        .from(gatewayTokens)
132	        .where(eq(gatewayTokens.installationId, installationId))
133	        .limit(1);
134	
135	      const tokenRow = tokenRows[0];
136	      if (!tokenRow) {
137	        log.info(
138	          "[connection-lifecycle] no token row found, skipping revocation",
139	          {
140	            installationId,
141	          }
142	        );
143	        return;
144	      }
145	
146	      try {
147	        const auth = providerDef.auth;
148	        if (auth.kind === "oauth" && auth.revokeToken) {
149	          const decryptedToken = await decrypt(
150	            tokenRow.accessToken,
151	            getEncryptionKey()
152	          );
153	          await auth.revokeToken(config as never, decryptedToken);
154	        }
155	        log.info("[connection-lifecycle] token revoked", {
156	          installationId,
157	          provider: providerName,
158	        });
159	      } catch (err) {
160	        log.warn(
161	          "[connection-lifecycle] token revocation failed (best-effort)",
162	          {
163	            installationId,
164	            provider: providerName,
165	            error: parseError(err),
166	          }
167	        );
168	      }
169	    });
170	
171	    // Step 4: Disconnect org integrations and log resource disconnection.
172	    // For user-initiated disconnects the app-layer cascade may have already
173	    // set orgIntegrations.status → 'disconnected', but for health-check
174	    // triggers no cascade runs. We update unconditionally (idempotent).
175	    await step.run("disconnect-resources", async () => {
176	      const allResources = await db
177	        .select({ providerResourceId: orgIntegrations.providerResourceId })
178	        .from(orgIntegrations)
179	        .where(eq(orgIntegrations.installationId, installationId));
180	
181	      if (allResources.length > 0) {
182	        const now = new Date().toISOString();
183	        await db
184	          .update(orgIntegrations)
185	          .set({
186	            status: "disconnected",
187	            statusReason: "installation_revoked",
188	            updatedAt: now,
189	          })
190	          .where(eq(orgIntegrations.installationId, installationId));
191	      }
192	
193	      const resourceIdMap: Record<string, string> = {};
194	      for (const r of allResources) {
195	        resourceIdMap[r.providerResourceId] = "disconnected";
196	      }
197	
198	      await db.insert(gatewayLifecycleLogs).values({
199	        installationId,
200	        event: "resources_removed",
201	        fromStatus: "revoked",
202	        toStatus: "revoked",
203	        reason: `Disconnected ${allResources.length} linked resource(s) during teardown`,
204	        resourceIds: resourceIdMap,
205	        metadata: { step: "disconnect-resources", triggeredBy: "system" },
206	      });
207	
208	      log.info("[connection-lifecycle] resources disconnected", {
209	        installationId,
210	        count: allResources.length,
211	      });
212	    });
213	
214	    log.info("[connection-lifecycle] teardown complete", {
215	      installationId,
216	      provider: providerName,
217	    });
218	
219	    return { success: true, installationId };
220	  }
221	);
