152	          // Build the API request from the entity handler
153	          const request = entityHandler.buildRequest(ctx, cursor);
154	          const api: ProviderApi = providerDef.api;
155	          const endpoint = api.endpoints[entityHandler.endpointId];
156	          if (!endpoint) {
157	            throw new NonRetriableError(
158	              `Unknown endpoint: ${entityHandler.endpointId}`
159	            );
160	          }
161	
162	          // Build URL
163	          let path = endpoint.path;
164	          if (request.pathParams) {
165	            for (const [key, val] of Object.entries(request.pathParams)) {
166	              path = path.replace(`{${key}}`, encodeURIComponent(val));
167	            }
168	          }
169	
170	          let url = `${api.baseUrl}${path}`;
171	          if (
172	            request.queryParams &&
173	            Object.keys(request.queryParams).length > 0
174	          ) {
175	            url += `?${new URLSearchParams(request.queryParams).toString()}`;
176	          }
177	
178	          // Build headers
