213	              response = await fetch(url, { ...fetchOptions, headers });
214	            }
215	          }
216	
217	          if (response.status === 401) {
218	            // Token is definitively revoked — fire health-check signal
219	            return {
220	              __healthCheckSignal: true as const,
221	              status: 401,
222	              events: [] as ReturnType<
223	                typeof entityHandler.processResponse
224	              >["events"],
225	              nextCursor: null,
226	              rawCount: 0,
227	              rateLimit: null,
