267	                  remaining: rateLimit.remaining,
268	                  resetAt: rateLimit.resetAt.toISOString(),
269	                  limit: rateLimit.limit,
270	                }
271	              : null,
272	          };
273	        }
274	      );
275	
276	      // Handle 401 health check signal outside of the step
277	      if (fetchResult.__healthCheckSignal) {
278	        await step.sendEvent("signal-connection-health-check", {
279	          name: "platform/health.check.requested",
280	          data: {
281	            installationId,
282	            provider,
283	            reason: "401_unauthorized" as const,
284	            correlationId,
285	          },
286	        });
