288	          `Provider API returned 401 — token revoked for installation ${installationId}. Health check signal sent.`
289	        );
290	      }
291	
292	      log.info("[entity-worker] page fetched", {
293	        installationId,
294	        entityType,
295	        resource: resource.providerResourceId,
296	        page: pageNum,
297	        events: fetchResult.events.length,
298	        ...(fetchResult.rateLimit && {
299	          rateLimitRemaining: fetchResult.rateLimit.remaining,
300	        }),
301	        correlationId,
302	      });
303	
304	      eventsProduced += fetchResult.events.length;
305	
306	      // Dispatch each event: hold for replay (DB insert) or send immediately (Inngest)
307	      const dispatched = await step.run(
308	        `dispatch-${entityType}-p${pageNum}`,
309	        async () => {
310	          const BATCH_SIZE = 5;
311	          const events = fetchResult.events;
312	          let count = 0;
313	
314	          for (let i = 0; i < events.length; i += BATCH_SIZE) {
315	            const batch = events.slice(i, i + BATCH_SIZE);
316	            if (batch.length === 0) {
317	              continue;
318	            }
319	
320	            if (holdForReplay) {
321	              // Persist to DB with status "held" — orchestrator replays after all workers finish
322	              await db
323	                .insert(gatewayWebhookDeliveries)
324	                .values(
325	                  batch.map((webhookEvent) => ({
326	                    provider,
327	                    deliveryId: webhookEvent.deliveryId,
328	                    eventType: webhookEvent.eventType,
329	                    installationId,
330	                    status: "held" as const,
331	                    payload: JSON.stringify(webhookEvent.payload),
332	                    receivedAt: new Date().toISOString(),
333	                  }))
334	                )
335	                .onConflictDoNothing();
336	            } else {
337	              // Send events to Inngest immediately
338	              await inngest.send(
339	                batch.map((webhookEvent) => ({
340	                  name: "platform/webhook.received" as const,
341	                  data: {
342	                    provider,
343	                    deliveryId: webhookEvent.deliveryId,
344	                    eventType: webhookEvent.eventType,
345	                    resourceId: null,
346	                    payload: webhookEvent.payload,
347	                    receivedAt: Date.now(),
348	                    preResolved: {
349	                      connectionId: installationId,
350	                      orgId,
351	                    },
352	                    correlationId,
353	                  },
354	                }))
355	              );
356	            }
357	            count += batch.length;
358	          }
359	          return count;
360	        }
361	      );
362	
363	      log.info("[entity-worker] page dispatched", {
364	        installationId,
365	        entityType,
366	        resource: resource.providerResourceId,
367	        page: pageNum,
368	        dispatched,
369	        correlationId,
370	      });
371	
372	      eventsDispatched += dispatched;
373	
374	      // Rate limit sleep if near threshold (dynamic, based on response headers)
375	      if (fetchResult.rateLimit) {
376	        const { remaining, resetAt, limit } = fetchResult.rateLimit;
377	        if (remaining < limit * 0.1) {
378	          const sleepMs = Math.max(0, new Date(resetAt).getTime() - Date.now());
379	          if (sleepMs > 0) {
380	            log.info("[entity-worker] rate limit sleep", {
381	              installationId,
382	              entityType,
383	              resource: resource.providerResourceId,
384	              sleepMs,
385	              resetAt,
386	              correlationId,
387	            });
388	            await step.sleep(
389	              `rate-limit-${entityType}-p${pageNum}`,
390	              `${Math.ceil(sleepMs / 1000)}s`
391	            );
392	          }
393	        }
394	      }
395	
396	      if (!fetchResult.nextCursor) {
397	        break;
398	      }
399	      if (pageNum >= MAX_PAGES) {
400	        log.warn(`[backfill] entity-worker hit MAX_PAGES cap (${MAX_PAGES})`, {
401	          installationId,
402	          entityType,
403	          resource: resource.providerResourceId,
404	          correlationId,
405	        });
406	        break;
407	      }
408	      cursor = fetchResult.nextCursor;
409	      pageNum++;
410	    }
411	
412	    log.info("[entity-worker] complete", {
413	      installationId,
414	      provider,
415	      entityType,
416	      resource: resource.providerResourceId,
417	      eventsProduced,
418	      eventsDispatched,
419	      pagesProcessed: pageNum,
420	      correlationId,
421	    });
422	
423	    return {
424	      entityType,
425	      resource: resource.providerResourceId,
426	      eventsProduced,
427	      eventsDispatched,
428	      pagesProcessed: pageNum,
429	    };
430	  }
431	);
