1	/**
2	 * Activity Recording Workflow
3	 *
4	 * Batched activity recording workflow for efficient database writes.
5	 * Receives activity events from helper functions and batch inserts them
6	 * for better performance and reduced database load.
7	 *
8	 * Triggered by: app/activity.record events (Tier 2 user actions)
9	 * Batching: Up to 100 events per batch, 10s timeout per org
10	 * Performance: 50-100x faster than individual inserts
11	 *
12	 * @see /docs/implementation/user-activity-tracking.md
13	 */
14	
15	import { db } from "@db/app/client";
16	import { orgUserActivities } from "@db/app/schema";
17	import type { ActivityMetadata } from "@repo/app-validation";
18	import { parseError } from "@vendor/observability/error/next";
19	import { log } from "@vendor/observability/log/next";
20	import { inngest } from "../../client/client";
21	
22	/**
23	 * Record Activity Workflow
24	 *
25	 * Processes batched activity events and inserts them into the database.
26	 * Uses Inngest's batch feature for efficient processing.
27	 */
28	export const recordActivity = inngest.createFunction(
29	  {
30	    id: "app/record-activity",
31	    name: "Record Activity",
32	    description: "Batch record user activities for efficient database writes",
33	    retries: 3,
34	
35	    // Batch configuration for optimal performance
36	    batchEvents: {
37	      maxSize: 100, // Process up to 100 events at once
38	      timeout: "10s", // Wait max 10s before processing partial batch
39	      key: "event.data.clerkOrgId", // Batch per org
40	    },
41	
42	    timeouts: {
43	      start: "30s",
44	      finish: "2m",
45	    },
46	  },
47	  { event: "app/activity.record" },
48	  async ({ events, step }) => {
49	    // Guard: Inngest's batchEvents config should never deliver an empty array,
50	    // but defend against it to avoid a Postgres error on INSERT with no values.
51	    if (events.length === 0) {
52	      log.warn("Received empty activity batch, skipping");
53	      return {
54	        success: true,
55	        clerkOrgId: undefined,
56	        batchSize: 0,
57	        insertedCount: 0,
58	        timestamp: new Date().toISOString(),
59	      };
60	    }
61	
62	    const batchSize = events.length;
63	    // Safe after the length guard above
64	    const clerkOrgId = events[0].data.clerkOrgId;
65	
66	    log.info("Processing activity batch", {
67	      batchSize,
68	      clerkOrgId,
69	      firstEventTimestamp: events[0].ts,
70	      lastEventTimestamp: events.at(-1)?.ts,
71	    });
72	
73	    // Step 1: Prepare activity records
74	    const activityRecords = await step.run("activity.prepare-records", () => {
75	      return events.map((event) => {
76	        const { data } = event;
77	
78	        return {
79	          clerkOrgId: data.clerkOrgId,
80	          category: data.category,
81	          action: data.action,
82	          entityType: data.entityType,
83	          entityId: data.entityId,
84	          // Cast metadata to preserve type safety after deserialization
85	          // Metadata is REQUIRED for all activities
86	          metadata: data.metadata as ActivityMetadata,
87	          relatedActivityId: data.relatedActivityId ?? null,
88	        };
89	      });
90	    });
91	
92	    // Step 2: Batch insert activities
93	    const insertResult = await step.run("activity.batch-insert", async () => {
94	      try {
95	        // Use Drizzle's batch insert for optimal performance
96	        const result = await db
97	          .insert(orgUserActivities)
98	          .values(activityRecords)
99	          .returning({ id: orgUserActivities.id });
100	
101	        log.info("Activity batch inserted", {
102	          clerkOrgId,
103	          insertedCount: result.length,
104	          batchSize,
105	        });
106	
107	        return {
108	          success: true,
109	          insertedCount: result.length,
110	          insertedIds: result.map((r) => r.id),
111	        };
112	      } catch (error) {
113	        log.error("Failed to insert activity batch", {
114	          clerkOrgId,
115	          batchSize,
116	          error: parseError(error),
117	        });
118	
119	        throw error;
120	      }
121	    });
122	
123	    return {
124	      success: true,
125	      clerkOrgId,
126	      batchSize,
127	      insertedCount: insertResult.insertedCount,
128	      timestamp: new Date().toISOString(),
129	    };
130	  }
131	);
