/**
 * Health check cron function
 *
 * Ported from apps/gateway/src/functions/health-check.ts
 *
 * KEY CHANGES vs gateway service:
 * - Function ID: platform/health.check (was apps-gateway/health.check)
 * - Fires platform/connection.lifecycle (was platform/connection.lifecycle)
 * - Uses providerConfigs from memory lib (was gateway env + runtime)
 */

import { db } from "@db/app/client";
import { gatewayInstallations, gatewayLifecycleLogs } from "@db/app/schema";
import type { ProviderDefinition, SourceType } from "@repo/app-providers";
import { getProvider } from "@repo/app-providers";
import { nanoid } from "@repo/lib";
import { eq, sql } from "@vendor/db";
import { log } from "@vendor/observability/log/next";
import { providerConfigs } from "../../lib/provider-configs";
import { getActiveTokenForInstallation } from "../../lib/token-helpers";
import { inngest } from "../client";

const FAILURE_THRESHOLD_DEGRADED = 3; // mark healthStatus='degraded'
const FAILURE_THRESHOLD_LIFECYCLE = 6; // fire lifecycle event (~30 min)

export const healthCheck = inngest.createFunction(
  {
    id: "platform/health.check",
    name: "Health Check (5m cron)",
    retries: 1,
    /**
     * Global concurrency: 1 — prevents overlapping cron runs.
     * If the previous run is still executing when the next cron fires,
     * Inngest queues the new run; it does not drop it.
     */
    concurrency: [{ limit: 1 }],
  },
  { cron: "*/5 * * * *" },
  async ({ step }) => {
    // -- Step 1: Fetch all active installations ----------------------------
    const installations = await step.run(
      "list-active-installations",
      async () => {
        return db
          .select({
            id: gatewayInstallations.id,
            provider: gatewayInstallations.provider,
            externalId: gatewayInstallations.externalId,
            orgId: gatewayInstallations.orgId,
            healthCheckFailures: gatewayInstallations.healthCheckFailures,
          })
          .from(gatewayInstallations)
          .where(eq(gatewayInstallations.status, "active"));
      }
    );

    log.info("[health-check] probing installations", {
      count: installations.length,
    });

    // -- Step 2: Probe each installation -----------------------------------
    for (const installation of installations) {
      const providerName = installation.provider as SourceType;
      const providerDef = getProvider(providerName);

      // Skip providers without a health check definition
      if (!providerDef?.healthCheck) {
        continue;
      }

      await step.run(`probe-${installation.id}`, async () => {
        const config = providerConfigs[providerName];

        if (!config) {
          log.warn("[health-check] provider not configured — skipping", {
            provider: providerName,
            installationId: installation.id,
          });
          return;
        }

        // Get the decrypted access token (handles on-demand refresh)
        let accessToken: string | null = null;
        try {
          const tokenResult = await getActiveTokenForInstallation(
            installation,
            config,
            providerDef as ProviderDefinition
          );
          accessToken = tokenResult.token;
        } catch (err) {
          log.warn(
            "[health-check] token fetch failed — recording transient failure",
            {
              installationId: installation.id,
              provider: providerName,
              error: err instanceof Error ? err.message : String(err),
            }
          );
          await recordTransientFailure(installation);
          return;
        }

        // Call provider health probe
        let status: Awaited<
          ReturnType<NonNullable<typeof providerDef.healthCheck>["check"]>
        >;
        try {
          status = await providerDef.healthCheck!.check(
            config as never,
            installation.externalId,
            accessToken
          );
        } catch (err) {
          log.warn(
            "[health-check] probe failed — recording transient failure",
            {
              installationId: installation.id,
              provider: providerName,
              error: err instanceof Error ? err.message : String(err),
            }
          );
          await recordTransientFailure(installation);
          return;
        }

        if (status === "healthy") {
          await db
            .update(gatewayInstallations)
            .set({
              healthStatus: "healthy",
              healthCheckFailures: 0,
              lastHealthCheckAt: new Date().toISOString(),
            })
            .where(eq(gatewayInstallations.id, installation.id));

          log.info("[health-check] healthy", {
            installationId: installation.id,
            provider: providerName,
          });
          return;
        }

        // revoked | suspended -> fire lifecycle event immediately
        log.warn("[health-check] auth failure — firing lifecycle", {
          installationId: installation.id,
          provider: providerName,
          status,
        });

        // Write lifecycle log row
        await db.insert(gatewayLifecycleLogs).values({
          id: nanoid(),
          installationId: installation.id,
          event: "health_check_revoked",
          fromStatus: "active",
          toStatus: "revoked",
          reason: `Health check returned "${status}"`,
          metadata: { connectionStatus: status },
        });

        // Fire platform/connection.lifecycle event (was platform/connection.lifecycle)
        await inngest.send({
          name: "platform/connection.lifecycle",
          data: {
            reason: "health_check_revoked",
            installationId: installation.id,
            orgId: installation.orgId,
            provider: providerName,
            triggeredBy: "health_check" as const,
          },
        });
      });
    }

    return { probed: installations.length };
  }
);

// -- Private helpers --------------------------------------------------------

async function recordTransientFailure(installation: {
  id: string;
  provider: string;
  orgId: string;
  healthCheckFailures: number;
}): Promise<void> {
  const newFailureCount = installation.healthCheckFailures + 1;
  const healthStatus =
    newFailureCount >= FAILURE_THRESHOLD_DEGRADED ? "degraded" : "unknown";

  await db
    .update(gatewayInstallations)
    .set({
      healthCheckFailures: sql`${gatewayInstallations.healthCheckFailures} + 1`,
      healthStatus,
      lastHealthCheckAt: new Date().toISOString(),
    })
    .where(eq(gatewayInstallations.id, installation.id));

  log.warn("[health-check] transient failure recorded", {
    installationId: installation.id,
    provider: installation.provider,
    newFailureCount,
    healthStatus,
  });

  // After FAILURE_THRESHOLD_LIFECYCLE consecutive failures (~30min), fire lifecycle
  if (newFailureCount >= FAILURE_THRESHOLD_LIFECYCLE) {
    await db.insert(gatewayLifecycleLogs).values({
      id: nanoid(),
      installationId: installation.id,
      event: "health_check_unreachable",
      fromStatus: "active",
      toStatus: "revoked",
      reason: `${newFailureCount} consecutive health check failures`,
      metadata: { consecutiveFailures: newFailureCount },
    });

    await inngest.send({
      name: "platform/connection.lifecycle",
      data: {
        reason: "health_check_unreachable",
        installationId: installation.id,
        orgId: installation.orgId,
        provider: installation.provider,
        triggeredBy: "health_check" as const,
      },
    });
  }
}

/**
 * Token refresh cron function
 *
 * Ported from apps/gateway/src/functions/token-refresh.ts
 *
 * KEY CHANGES vs gateway service:
 * - Function ID: platform/token.refresh (was apps-gateway/token.refresh)
 * - Uses providerConfigs from memory lib (was gateway env + runtime)
 */

import { db } from "@db/app/client";
import { gatewayInstallations, gatewayTokens } from "@db/app/schema";
import type { SourceType } from "@repo/app-providers";
import { getProvider } from "@repo/app-providers";
import { decrypt } from "@repo/lib";
import { and, eq, isNotNull, lt } from "@vendor/db";
import { parseError } from "@vendor/observability/error/next";
import { log } from "@vendor/observability/log/next";
import { getEncryptionKey } from "../../lib/encryption";
import { providerConfigs } from "../../lib/provider-configs";
import { updateTokenRecord } from "../../lib/token-store";
import { inngest } from "../client";

/** Refresh tokens expiring within this window. */
const REFRESH_WINDOW_MS = 10 * 60 * 1000; // 10 minutes

export const tokenRefresh = inngest.createFunction(
  {
    id: "platform/token.refresh",
    name: "Token Refresh (5m cron)",
    retries: 2,
    concurrency: [{ limit: 1 }],
  },
  { cron: "*/5 * * * *" },
  async ({ step }) => {
    // -- Step 1: Find installations with expiring tokens --------------------
    const expiringSoon = await step.run("list-expiring-tokens", async () => {
      const cutoff = new Date(Date.now() + REFRESH_WINDOW_MS).toISOString();

      return db
        .select({
          installationId: gatewayTokens.installationId,
          tokenId: gatewayTokens.id,
          encryptedRefreshToken: gatewayTokens.refreshToken,
          expiresAt: gatewayTokens.expiresAt,
          provider: gatewayInstallations.provider,
          externalId: gatewayInstallations.externalId,
          orgId: gatewayInstallations.orgId,
        })
        .from(gatewayTokens)
        .innerJoin(
          gatewayInstallations,
          eq(gatewayTokens.installationId, gatewayInstallations.id)
        )
        .where(
          and(
            eq(gatewayInstallations.status, "active"),
            isNotNull(gatewayTokens.refreshToken),
            isNotNull(gatewayTokens.expiresAt),
            lt(gatewayTokens.expiresAt, cutoff)
          )
        );
    });

    log.info("[token-refresh] tokens expiring soon", {
      count: expiringSoon.length,
    });

    // -- Step 2: Refresh each token -----------------------------------------
    let refreshedCount = 0;

    for (const row of expiringSoon) {
      await step.run(`refresh-${row.installationId}`, async () => {
        const providerName = row.provider as SourceType;
        const providerDef = getProvider(providerName);

        if (!providerDef) {
          return;
        }

        const auth = providerDef.auth;
        if (auth.kind !== "oauth" || !auth.refreshToken) {
          // Provider doesn't support token refresh — skip
          return;
        }

        const config = providerConfigs[providerName];

        if (!config) {
          log.warn("[token-refresh] provider not configured — skipping", {
            provider: providerName,
            installationId: row.installationId,
          });
          return;
        }

        try {
          const decryptedRefresh = await decrypt(
            row.encryptedRefreshToken!,
            getEncryptionKey()
          );
          const refreshed = await auth.refreshToken(
            config as never,
            decryptedRefresh
          );
          await updateTokenRecord(
            row.tokenId,
            refreshed,
            row.encryptedRefreshToken,
            row.expiresAt
          );

          refreshedCount++;
          log.info("[token-refresh] token refreshed", {
            installationId: row.installationId,
            provider: providerName,
          });
        } catch (err) {
          // Refresh failure is logged but not fatal — the request-time refresh
          // path in getActiveTokenForInstallation() is the fallback.
          log.warn("[token-refresh] refresh failed", {
            installationId: row.installationId,
            provider: providerName,
            error: parseError(err),
          });
        }
      });
    }

    return { refreshed: refreshedCount };
  }
);

/**
 * Delivery recovery cron function
 *
 * Replaces QStash-scheduled POST /admin/recovery/cron in the relay service.
 * Source logic: apps/relay/src/lib/replay.ts + apps/relay/src/routes/admin.ts (lines 224-249)
 *
 * Sweeps all deliveries stuck in status='received' for more than 5 minutes
 * across all providers and installations, then sends platform/webhook.received
 * events for each one instead of re-triggering Upstash Workflows.
 */

import { db } from "@db/app/client";
import { gatewayInstallations, gatewayWebhookDeliveries } from "@db/app/schema";
import type { SourceType } from "@repo/app-providers";
import { getProvider, isWebhookProvider } from "@repo/app-providers";
import { and, eq, lt } from "@vendor/db";
import { log } from "@vendor/observability/log/next";
import { inngest } from "../client";

export const deliveryRecovery = inngest.createFunction(
  {
    id: "platform/delivery.recovery",
    name: "Delivery Recovery (5m cron)",
    retries: 1,
    concurrency: [{ limit: 1 }],
  },
  { cron: "*/5 * * * *" },
  async ({ step }) => {
    const BATCH_SIZE = 100;
    const STALE_THRESHOLD_MS = 5 * 60 * 1000; // 5 minutes

    // -- Step 1: Find stuck deliveries --------------------------------------
    const deliveries = await step.run("find-stuck-deliveries", async () => {
      const staleBeforeIso = new Date(
        Date.now() - STALE_THRESHOLD_MS
      ).toISOString();

      return db
        .select()
        .from(gatewayWebhookDeliveries)
        .where(
          and(
            eq(gatewayWebhookDeliveries.status, "received"),
            lt(gatewayWebhookDeliveries.receivedAt, staleBeforeIso)
          )
        )
        .orderBy(gatewayWebhookDeliveries.receivedAt)
        .limit(BATCH_SIZE);
    });

    if (deliveries.length === 0) {
      return { replayed: 0, skipped: 0, failed: 0 };
    }

    log.info("[delivery-recovery] found stuck deliveries", {
      count: deliveries.length,
    });

    // -- Step 2: Re-send each as platform/webhook.received --------------------
    const result = await step.run("replay-deliveries", async () => {
      const replayed: string[] = [];
      const skipped: string[] = [];
      const failed: string[] = [];

      for (const delivery of deliveries) {
        if (!delivery.payload) {
          skipped.push(delivery.deliveryId);
          continue;
        }

        try {
          const parsedPayload = JSON.parse(delivery.payload) as unknown;
          const providerName = delivery.provider as SourceType;

          // Re-extract resourceId from stored payload via provider
          let resourceId: string | null = null;
          try {
            const providerDef = getProvider(providerName);
            if (providerDef && isWebhookProvider(providerDef)) {
              resourceId =
                providerDef.webhook.extractResourceId(parsedPayload) ?? null;
            }
          } catch (err) {
            log.warn(
